INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VTK_2020_consolidated', 'VTK', 2020, 'consolidated', 'Doanh nghiệp có giao dịch đáng kể với bên liên quan là công ty mẹ và các công ty con, tập trung rủi ro vào Tập đoàn Viettel. Các giao dịch chủ yếu là doanh thu bán hàng dịch vụ tư vấn thiết kế, không có dấu hiệu giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Doanh nghiệp không có nợ vay tài chính, chỉ có nợ phải trả ngắn hạn là các khoản phải trả người bán và chi phí phải trả. Khả năng thanh toán tốt từ dòng tiền hoạt động kinh doanh, rủi ro thanh khoản thấp.', 'Hàng tồn kho và dự án đầu tư xây dựng có giá trị nhỏ, không có dự án bất động sản lớn hay tồn kho ứ đọng. Rủi ro tồn kho không đáng kể.', 4, 'Công ty có kết quả kinh doanh ổn định, lợi nhuận sau thuế tăng trưởng nhẹ. Không có nợ vay, dòng tiền từ hoạt động kinh doanh mạnh. Tuy nhiên, doanh thu phụ thuộc lớn vào công ty mẹ và các đơn vị liên kết. Sức khỏe tài chình tốt, triển vọng đầu tư an toàn nhưng tăng trưởng có thể hạn chế do phụ thuộc vào Tập đoàn Viettel.'),
('VTK_2019_consolidated', 'VTK', 2019, 'consolidated', 'Công ty có giao dịch lớn với bên liên quan, chủ yếu là doanh thu từ Tập đoàn Công nghiệp - Viễn thông Quân đội và các công ty con, cho thấy sự phụ thuộc cao vào công ty mẹ. Tuy nhiên, không có dấu hiệu giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ ngắn hạn tăng chủ yếu từ phải trả người bán và chi phí phải trả, không có nợ vay ngân hàng dài hạn. Công ty có tiền mặt và đầu tư tài chính ngắn hạn lớn, đảm bảo khả năng thanh toán nợ đến hạn.', 'Hàng tồn kho và dự án xây dựng dở dang có giá trị không lớn, rủi ro thấp. Dự án mua văn phòng đang hoàn tất thủ tục pháp lý, chưa phát sinh vấn đề ứ đọng.', 3, 'Công ty có kết quả kinh doanh khả quan với doanh thu và lợi nhuận tăng trưởng, dòng tiền từ hoạt động kinh doanh dương. Tuy nhiên, sự phụ thuộc lớn vào Tập đoàn Công nghiệp - Viễn thông Quân đội là rủi ro đáng chú ý. Tình hình tài chính ổn định với nợ thấp và tài sản dồi dào.'),
('VTK_2021_consolidated', 'VTK', 2021, 'consolidated', 'Công ty có doanh thu bán hàng chủ yếu từ các bên liên quan (trên 80% doanh thu), tạo ra sự phụ thuộc lớn và có nguy cơ giao dịch không công bằng với công ty mẹ và các đơn vị phụ thuộc.', 'Công ty không có nợ vay ngân hàng, nợ phải trả chủ yếu là thương mại và thuế, khả năng thanh toán tốt với tiền mặt và tương đương tiền dồi dào.', 'Hàng tồn kho chủ yếu là chi phí sản xuất dở dang với giá trị nhỏ, rủi ro thấp do không có dự phòng giảm giá.', 5, 'Tình hình tài chính của công ty ổn định, lợi nhuận tăng trưởng, nhưng sự phụ thuộc vào công ty mẹ là đáng lo ngại. Khả năng sinh lời tốt, thanh khoản mạnh, nhưng cần theo dõi rủi ro từ giao dịch liên quan và quản trị công ty.'),
('VTK_2018_consolidated', 'VTK', 2018, 'consolidated', 'Doanh thu từ các bên liên quan (chủ yếu là Tập đoàn Viettel và các công ty con) chiếm tỷ trọng rất lớn (~93.7%) trong tổng doanh thu, cho thấy sự phụ thuộc cao vào tập đoàn mẹ. Các giao dịch được thực hiện theo thỏa thuận nhưng có thể không hoàn toàn phản ánh giá thị trường.', 'Công ty không có nợ vay ngân hàng, chỉ có các khoản phải trả ngắn hạn (thương mại, lương, thuế). Nợ ngắn hạn ở mức 26.090 triệu VND, chủ yếu là phải trả người lao động và chi phí phải trả, áp lực trả nợ thấp.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang (công trình xây dựng), giá trị nhỏ (137 triệu VND) và không có dự phòng. Rủi ro ứ đọng thấp.', 5, 'Công ty có kết quả kinh doanh ổn định với lợi nhuận sau thuế ~17.880 triệu VND, không có nợ vay, dòng tiền từ hoạt động kinh doanh dương. Tuy nhiên, doanh thu phụ thuộc lớn vào tập đoàn mẹ Viettel, gây rủi ro tập trung khách hàng. Sức khỏe tài chính cơ bản tốt, triển vọng ổn định nhưng hạn chế tăng trưởng nếu không đa dạng hóa khách hàng.'),
('VTK_2016_consolidated', 'VTK', 2016, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là doanh thu bán hàng và phải thu ngắn hạn với Tập đoàn Viễn thông Quân đội (công ty mẹ) và các đơn vị phụ thuộc, không có điều kiện bất thường được đề cập, nhưng mức độ tập trung cao vào công ty mẹ.', 'Doanh nghiệp không có nợ vay tài chính, chỉ có các khoản phải trả ngắn hạn như phải trả người bán và thuế, với khả năng thanh toán tốt từ dòng tiền kinh doanh.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang với giá trị giảm và không trích lập dự phòng, rủi ro thấp.', 3, 'Doanh nghiệp có tình hình tài chính khỏe mạnh, lợi nhuận tăng trưởng ổn định, thanh khoản tốt với tiền và tương đương tiền lớn, không có nợ vay và tập trung vào hoạt động kinh doanh chính với công ty mẹ. Điểm rủi ro quản trị thấp do giao dịch với bên liên quan minh bạch và không có dấu hiệu bất thường.'),
('VTK_2017_consolidated', 'VTK', 2017, 'consolidated', 'Doanh nghiệp có giao dịch lớn với công ty mẹ, chiếm hơn 90% doanh thu và phải thu. Điều này tạo rủi ro phụ thuộc, nhưng không có bằng chứng giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty không có nợ vay, áp lực nợ thấp, khả năng thanh toán tốt từ dòng tiền hoạt động kinh doanh.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang cho các dự án tư vấn. Không có dự phòng, nhưng cần theo dõi tiến độ dự án để tránh ứ đọng.', 3, 'Công ty có sức khỏe tài chính tốt với biên lợi nhuận gộp cao (khoảng 33.6%), không nợ vay, và dòng tiền ổn định. Tuy nhiên, phụ thuộc lớn vào công ty mẹ là rủi ro tiềm ẩn. Triển vọng đầu tư tích cực nếu duy trì được quan hệ với bên liên quan và quản lý rủi ro tồn kho.'),
('VTJ_2025_consolidated', 'VTJ', 2025, 'consolidated', 'Doanh thu bán hàng hóa 8,94 tỷ VNĐ trong năm phát sinh toàn bộ từ một bên liên quan là Tổng Công ty Chè Việt Nam - CTCP (chung thành viên quản lý chủ chốt). Mức độ tập trung doanh thu vào một bên liên quan là rất cao, tạo ra rủi ro phụ thuộc và cần được theo dõi tính công bằng của giá giao dịch. Công ty cũng có khoản phải trả 100 triệu VNĐ cho Chủ tịch Lê Chí Long.', 'Áp lực nợ vay thấp. Công ty không có vay nợ ngân hàng (chi phí lãi vay bằng 0). Nợ chủ yếu là phải trả người bán và thuế. Nợ dài hạn là thuế thu nhập hoãn lại phải trả (5,25 tỷ VNĐ), không phải nợ vay truyền thống. Khả năng thanh toán ngắn hạn ổn định với tiền mặt (853 triệu VNĐ) và các khoản phải thu.', 'Rủi ro tồn kho rất thấp. Hàng tồn kho cuối kỳ bằng 0. Các khoản đầu tư dở dang là chi phí mua đất nền và thiết kế (tổng ~4,96 tỷ VNĐ) cho dự án xây dựng nhà ở, đang chờ thủ tục pháp lý.', 5, 'Tập đoàn có sức khỏe tài chính an toàn với cơ cấu tài chính chủ yếu bằng vốn chủ sở hữu (97,2 tỷ VNĐ), không vay nợ ngân hàng và có dòng tiền kinh doanh dương. Tuy nhiên, doanh thu tập trung cao vào một bên liên quan, lợi nhuận mỏng (biên lợi nhuận gộp ~1.6%), và hiệu quả đầu tư vào công ty liên kết còn thấp (lỗ lũy kế lớn). Công ty có tài sản dở dang là đất nền, giá trị tiềm năng cần được đánh giá. Điểm rủi ro quản trị ở mức trung bình do giao dịch tập trung với bên liên quan.'),
('VTJ_2025_parent', 'VTJ', 2025, 'parent', 'Rủi ro cao: 100% doanh thu bán hàng hóa (8.941.868.000 VNĐ) phát sinh từ giao dịch với Tổng Công ty Chè Việt Nam - CTCP, một bên liên quan chung thành viên quản lý chủ chốt. Công ty có khoản phải thu ngắn hạn 652.475.520 VNĐ từ bên liên quan này. Ngoài ra, Chủ tịch HĐQT Lê Chí Long có khoản phải trả 100 triệu VNĐ chưa rõ bản chất. Công ty cũng có đầu tư lớn vào công ty liên kết (Thái Sơn) với dự phòng tổn thất lên đến 22,3 tỷ VNĐ, cho thấy khoản đầu tư này có vấn đề.', 'Rủi ro thấp: Công ty không có nợ vay ngân hàng hay trái phiếu dài hạn. Nợ ngắn hạn chủ yếu là phải trả người bán (642 triệu) và phải trả cổ tức/lợi nhuận (1,77 tỷ). Công ty có lượng tiền mặt dồi dào (775,8 tỷ VNĐ) gấp gần 300 lần nợ ngắn hạn, đảm bảo khả năng thanh toán tốt. Không có tài sản thế chấp cho đơn vị khác.', 'Rủi ro trung bình cao: Chi phí xây dựng cơ bản dở dang 4,96 tỷ VNĐ đã treo từ năm 2017 (hợp đồng ký ngày 30/03/2017) đến nay vẫn chưa hoàn thành thủ tục chuyển nhượng giấy chứng nhận quyền sử dụng đất. Khoản đầu tư này đã chiếm dụng vốn gần 8 năm mà chưa phát sinh lợi ích kinh tế.', 7, 'Công ty có quy mô nhỏ với vốn điều lệ 114 tỷ VNĐ nhưng lợi nhuận sau thuế chưa phân phối âm lũy kế (-15,2 tỷ VNĐ) do thua lỗ các năm trước. Điểm mạnh là thanh khoản tốt (tiền mặt 775,8 tỷ) và không có nợ vay tài chính. Điểm yếu nghiêm trọng là phụ thuộc hoàn toàn vào một bên liên quan cho doanh thu, biên lợi nhuận gộp cực thấp (1,64%), khoản đầu tư liên kết có dự phòng lớn, và đất nền dở dang treo nhiều năm. Công ty đang trong quá trình hồi phục nhưng tiềm ẩn rủi ro về tính độc lập trong kinh doanh và hiệu quả sử dụng vốn.'),
('VTK_2015_consolidated', 'VTK', 2015, 'consolidated', 'Công ty có giao dịch lớn với công ty mẹ là Tập đoàn Viễn thông Quân đội, chiếm phần lớn doanh thu, tạo sự phụ thuộc nhưng không thấy giao dịch bất thường.', 'Công ty không có nợ vay, chỉ có các khoản phải trả nhà cung cấp ngắn hạn, áp lực nợ thấp.', 'Hàng tồn kho là chi phí sản xuất kinh doanh dở dang, giảm so với đầu năm và không có dự phòng, cho thấy tiến độ dự án ổn định.', 3, 'Công ty có tình hình tài chính lành mạnh, lợi nhuận tăng trưởng, tiền mặt dồi dào, nhưng tập trung kinh doanh vào công ty mẹ.'),
('VTJ_2024_consolidated', 'VTJ', 2024, 'consolidated', 'Công ty có giao dịch chuyển nhượng cổ phần cho cá nhân (bà Nguyễn Thị Trang) và hợp đồng hợp tác kinh doanh với Công ty Cổ phần Nông nghiệp TLK. Giá trị giao dịch lớn nhưng đã được thanh toán, không có dấu hiệu giao dịch bất thường rõ ràng.', 'Công ty không có nợ vay cuối năm, chỉ còn thuế thu nhập hoãn lại phải trả. Áp lực nợ vay thấp.', 'Không có hàng tồn kho, nhưng có dự án xây dựng dở dang (Văn phòng Vinataba) trị giá gần 5 tỷ đồng, cần theo dõi tiến độ triển khai.', 3, 'Công ty không phát sinh doanh thu từ hoạt động kinh doanh thương mại năm 2024, lợi nhuận chủ yếu từ hoạt động đầu tư tài chính. Tổng tài sản lớn (104 tỷ) nhưng chủ yếu là đầu tư dài hạn và phải thu. Cần cải thiện hoạt động kinh doanh cốt lõi để tạo doanh thu và dòng tiền ổn định.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VTJ_2023_consolidated', 'VTJ', 2023, 'consolidated', 'Không phát sinh giao dịch với các bên liên quan trong năm tài chính.', 'Doanh nghiệp không có nợ vay tài chính, chỉ có thuế thu nhập hoãn lại phải trả, áp lực nợ thấp.', 'Chi phí xây dựng dở dang ổn định, không có rủi ro ứ đọng hay giảm giá.', 3, 'Tập đoàn có kết quả kinh doanh tích cực với lợi nhuận sau thuế tăng trưởng, tài chính lành mạnh, không có giao dịch bên liên quan đáng ngờ, nợ vay không đáng kể. Tuy nhiên, doanh thu phụ thuộc chủ yếu vào hoạt động đầu tư tài chính.'),
('VTJ_2024_parent', 'VTJ', 2024, 'parent', 'Công ty có cấu trúc đầu tư phức tạp với công ty con VTJ Việt Nam (100%), công ty liên kết Thái Sơn (39,20%), và Quỹ Đầu tư Hạ tầng Red One (9,375%). Dự phòng giảm giá đầu tư vào công ty liên kết Thái Sơn ở mức cao (~58% giá gốc, 22,8 tỷ VND trên 39,2 tỷ VND giá gốc), cho thấy khoản đầu tư này có rủi ro lớn. Trong năm, Công ty đã chuyển nhượng 130.000 cổ phần Thái Sơn cho cá nhân bên ngoài (bà Nguyễn Thị Trang) với giá 9.000 đồng/cổ phần, giá trị ghi sổ dự kiến cao hơn đáng kể, đặt câu hỏi về tính minh bạch của giao dịch. Tuy nhiên, Công ty không phát sinh giao dịch bán hàng/dịch vụ nào với các thành viên quản lý chủ chốt trong năm.', 'Áp lực nợ vay thấp: Công ty không có nợ vay ngân hàng, không có nợ dài hạn. Tổng nợ phải trả chỉ ~1,94 tỷ VND (chủ yếu là cổ tức phải trả 1,78 tỷ VND và phải trả người bán 81 triệu VND). Công ty có tài sản tài chính dài hạn ~95,4 tỷ VND (bao gồm đầu tư vào công ty con, liên kết và đơn vị khác). Tiền mặt cuối kỳ giảm mạnh từ 480 triệu xuống 61 triệu VND do dòng tiền hoạt động kinh doanh âm và trả cổ tức.', 'Chi phí xây dựng cơ bản dở dang 4,96 tỷ VND là dự án mua đất và thiết kế cho Văn phòng Vi Na Ta Ba tại TP. Hồ Chí Minh. Dự án không có tiến triển trong năm (số liệu không đổi so với năm trước), cho thấy dự án bị đình trệ hoặc chưa được triển khai xây dựng. Không có hàng tồn kho thương mại.', 5, 'Công ty là công ty holding đầu tư, không phát sinh doanh thu bán hàng năm 2024 (so với ~5,9 tỷ VND năm trước). Lợi nhuận sau thuế chỉ 175 triệu VND (giảm mạnh so với 3,57 tỷ VND năm trước), chủ yếu đến từ hoàn nhập dự phòng đầu tư 874 triệu VND và lãi từ hoạt động đầu tư 130 triệu VND, bù đắp chi phí quản lý 570 triệu VND. Vốn chủ sở hữu 99,7 tỷ VND với lỗ lũy kế chưa phân phối 15,3 tỷ VND. Công ty có cấu trúc tài sản tập trung vào đầu tư dài hạn (~95,4 tỷ VND) với dự phòng giảm giá lớn (~22,8 tỷ VND), dự án bất động sản dở dang (~5 tỷ VND) chưa triển khai, và dòng tiền hoạt động kinh doanh âm liên tục hai năm. Triển vọng phụ thuộc lớn vào hiệu quả hoạt động của các khoản đầu tư và khả năng khai thác dự án bất động sản.'),
('VTJ_2022_consolidated', 'VTJ', 2022, 'consolidated', 'Công ty có giao dịch vay ngắn hạn với công ty con (Công ty TNHH Thương mại và Dịch vụ VTJ Việt Nam) với lãi suất thấp (4%/năm) và hình thức tín chấp. Đây là giao dịch nội bộ không có tài sản bảo đảm, có thể tiềm ẩn rủi ro về quản trị do công ty con không có nghĩa vụ trả nợ nếu hoạt động kém.', 'Nợ vay ngắn hạn chủ yếu từ công ty con với lãi suất cố định 4%/năm. Áp lực nợ vay không lớn do công ty đã trả phần lớn nợ trong kỳ (giảm từ 10 tỷ xuống 1,5 tỷ). Tuy nhiên, cấu trúc nợ phụ thuộc vào bên liên quan.', 'Công ty không có hàng tồn kho, nhưng có dự án xây dựng dở dang (dự án Văn phòng Vĩ na ta ba) trị giá hơn 4,9 tỷ VND đã treo nguyên giá từ đầu năm, không có biến động trong kỳ. Dự án này có thể bị ứ đọng hoặc chậm tiến độ.', 5, 'Công ty hoạt động chủ yếu với tư cách là công ty đầu tư tài chính, không có doanh thu bán hàng trong năm 2022. Lợi nhuận chủ yếu đến từ hoạt động tài chính (lãi bán đầu tư, lãi tiền gửi). Công ty có khoản đầu tư lớn vào công ty con và liên kết nhưng đã trích lập dự phòng giảm giá đáng kể. Dự án xây dựng dở dang cần theo dõi tiến độ. Sức khỏe tài chính trung bình, phụ thuộc lớn vào hoạt động đầu tư và giao dịch nội bộ.'),
('VTJ_2023_parent', 'VTJ', 2023, 'parent', 'Công ty có khoản vay ngắn hạn từ công ty con VTJ Việt Nam với giá trị 1,5 tỷ VNĐ đã được trả hết trong năm 2023. Công ty không phát sinh giao dịch mua bán hàng hóa/dịch vụ với các thành viên quản lý chủ chốt. Tuy nhiên, cấu trúc công ty mẹ-con-liên kết phức tạp với dự phòng đầu tư tài chính dài hạn lớn (hơn 23,7 tỷ VNĐ) cần được theo dõi sát.', 'Rủi ro nợ vay thấp: Không còn vay ngân hàng ngắn hạn cuối kỳ, nợ phải trả chủ yếu là phải trả người bán ngắn hạn (90 triệu), thuế phải nộp (6,1 triệu) và cổ tức, lợi nhuận phải trả (1,79 tỷ). Áp lực trả nợ ngắn hạn không đáng kể.', 'Công ty không có hàng tồn kho. Dự án xây dựng dở dang (Văn phòng Vi Na Ta Ba) trị giá gần 5 tỷ VNĐ là tài sản dài hạn, chưa có dấu hiệu bị ứ đọng hay suy giảm giá trị.', 5, 'Công ty có doanh thu khiêm tốn (~5,9 tỷ VNĐ) nhưng biên lợi nhuận gộp rất thấp (2,16%), cho thấy hoạt động kinh doanh chính kém hiệu quả. Lợi nhuận sau thuế 3,57 tỷ VNĐ chủ yếu đến từ hoàn nhập dự phòng đầu tư tài chính dài hạn (4,47 tỷ) và không phải từ hoạt động kinh doanh cốt lõi. Công ty có vốn chủ sở hữu âm lũy kế (-15,5 tỷ VNĐ), dòng tiền hoạt động kinh doanh âm (-523 triệu), tiềm ẩn rủi ro về khả năng hoạt động liên tục trong dài hạn.'),
('VTJ_2021_consolidated', 'VTJ', 2021, 'consolidated', 'Công ty có đầu tư vào công ty liên kết (Công ty Cổ phần Sản xuất Ứng dụng Công nghệ cao Thái Sơn) với giá trị ghi sổ giảm từ 38.954.716.072 VND xuống 23.221.036.582 VND trong năm, cho thấy rủi ro suy giảm giá trị đầu tư. Tuy nhiên, công ty không phát sinh giao dịch bán hàng, dịch vụ hay các giao dịch khác với các bên liên quan.', 'Công ty không có nợ vay có lãi suất. Nợ phải trả chủ yếu là nợ ngắn hạn thương mại (phải trả người bán, thuế) và thuế thu nhập hoãn lại. Rủi ro nợ thấp do không có áp lực trả nợ gốc và lãi định kỳ.', 'Công ty không có hàng tồn kho. Dự án xây dựng dở dang ''Văn phòng Vinataba'' có giá trị không thay đổi trong năm (4.958.635.200 VND), cho thấy dự án có thể bị đình trệ hoặc chưa triển khai xây dựng.', 4, 'Công ty có doanh thu ổn định nhưng lợi nhuận sau thuế âm (-1.232.189.870 VND) do lỗ từ hoạt động đầu tư tài chính. Tình hình tài chính còn nhiều khó khăn, với vốn chủ sở hữu bị giảm do lỗ lũy kế. Dự án bất động sản dở dang chưa tạo ra doanh thu. Công ty cần cải thiện hiệu quả hoạt động đầu tư và đẩy nhanh tiến độ dự án.'),
('VTJ_2020_parent', 'VTJ', 2020, 'parent', 'Giao dịch với bên liên quan bao gồm góp vốn vào công ty con (49 tỷ VND) và nhận cổ tức từ công ty liên kết (319 triệu VND). Công ty đã trích lập dự phòng giảm giá đầu tư tài chính dài hạn lớn (tăng từ 2.15 tỷ lên 22.85 tỷ), cho thấy rủi ro đầu tư cao vào các bên liên quan.', 'Công ty không có nợ vay ngân hàng, chỉ có các khoản phải trả ngắn hạn không đáng kể (tổng nợ phải trả 2.5 tỷ VND). Áp lực nợ thấp, không có tài sản thế chấp nổi bật.', 'Không có hàng tồn kho. Có dự án xây dựng dở dang (Văn phòng Vinataba) với giá trị gần 5 tỷ VND, có nguy cơ ứ đọng nếu không triển khai hoặc chuyển đổi mục đích sử dụng.', 7, 'Công ty lỗ nặng năm 2020 với lỗ sau thuế hơn 21 tỷ VND. Doanh thu chủ yếu từ thanh lý bất động sản đầu tư. Các khoản đầu tư vào công ty con và liên kết bị giảm giá mạnh, dẫn đến trích lập dự phòng lớn. Công ty đang tái cấu trúc và tìm kiếm chiến lược kinh doanh mới, hoạt động truyền thống (kinh doanh thuốc lá) đã ngừng.'),
('VTJ_2020_consolidated', 'VTJ', 2020, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là nhận cổ tức từ công ty liên kết với giá trị 319 triệu VNĐ, không có giao dịch bất thường đáng ngờ. Không phát sinh giao dịch bán hàng/dịch vụ hay cho vay với các thành viên quản lý chủ chốt.', 'Tập đoàn không có nợ vay ngân hàng. Nợ phải trả chủ yếu là thuế thu nhập hoãn lại phải trả (gần 5 tỷ VNĐ) và các khoản phải trả ngắn hạn khác (~2.5 tỷ VNĐ). Áp lực nợ vay thấp do không có nợ lãi suất, tuy nhiên công ty đang trong giai đoạn tái cấu trúc và ngừng hoạt động kinh doanh chính.', 'Hàng tồn kho bằng 0. Có dự án xây dựng dở dang (Văn phòng Vinataba) trị giá gần 5 tỷ VNĐ. Rủi ro dự án bị ứ đọng hoặc chậm tiến độ là có thể xảy ra trong bối cảnh thị trường bất động sản khó khăn và công ty đang tìm hướng kinh doanh mới.', 4, 'Tập đoàn đang trong giai đoạn tái cấu trúc mạnh mẽ, đã ngừng hoạt động kinh doanh thuốc lá truyền thống. Kết quả kinh doanh năm 2020 lỗ ròng gần 25 tỷ VNĐ, chủ yếu do lỗ từ đầu tư vào công ty liên kết và trích lập dự phòng. Tình hình tài chính còn nợ thuế hoãn lại đáng kể. Triển vọng đầu tư phụ thuộc vào khả năng tái cấu trúc và tìm kiếm chiến lược kinh doanh mới thành công.'),
('VTI_2025_consolidated', 'VTI', 2025, 'consolidated', 'Rủi ro cao. Công ty có giao dịch đáng kể với các bên liên quan, đặc biệt là khoản nợ phải trả 204 tỷ đồng cho các cá nhân liên quan đến việc chuyển quyền đòi nợ chưa hoàn tất. Khoản vay từ Tổng công ty May Hưng Yên (bên liên kết) đã quá hạn. Các giao dịch này có thể không theo điều kiện thị trường bình thường.', 'Rủi ro cực kỳ cao. Nợ ngắn hạn (218 tỷ đồng) vượt xa tài sản ngắn hạn, vốn chủ sở hữu âm lớn. Công ty phụ thuộc vào các khoản vay cá nhân và tái cơ cấu nợ. Khả năng thanh toán ngắn hạn rất yếu.', 'Thấp. Hàng tồn kho giá trị nhỏ (53,7 triệu đồng) và đã được trích lập dự phòng giảm giá toàn bộ.', 9, 'Công ty đang trong tình trạng tài chính nghiêm trọng với lỗ lũy kế lớn, vốn chủ sở hữu âm và mất khả năng thanh toán ngắn hạn. Triển vọng hoạt động liên tục phụ thuộc hoàn toàn vào việc tái cấu trúc thành công và sự hỗ trợ từ các cổ đông và cá nhân liên quan. Rủi ro đầu tư là rất cao.'),
('VTI_2023_consolidated', 'VTI', 2023, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với công ty mẹ, bao gồm vay nợ và miễn lãi vay, cho thấy sự phụ thuộc cao và rủi ro giao dịch bất thường có thể xảy ra.', 'Công ty đã thanh toán toàn bộ nợ vay ngân hàng trong năm 2023, nhưng vẫn duy trì lỗ lũy kế lớn và vốn chủ sở hữu âm, áp lực nợ ngắn hạn vẫn cao với số dư nợ ngắn hạn vượt tài sản ngắn hạn.', 'Hàng tồn kho có giá trị nhỏ và đã trích lập dự phòng giảm giá đầy đủ, rủi ro thấp.', 7, 'Tình hình tài chính của công ty yếu với lỗ lũy kế và vốn chủ sở hữu âm. Trong năm 2023, công ty đã được miễn lãi vay từ ngân hàng và đạt lợi nhuận, nhưng triển vọng phụ thuộc vào việc tái cấu trúc tài chính và bán nợ phải thu. Rủi ro đầu tư cao.'),
('VTI_2024_consolidated', 'VTI', 2024, 'consolidated', 'Doanh nghiệp có quan hệ giao dịch phức tạp với các bên liên quan trong Tập đoàn Dệt may Việt Nam. Tổng công ty May Hưng Yên (cổ đông >5% vốn điều lệ, bên liên kết của Công ty mẹ) cho vay 3,5 tỷ đồng đã quá hạn thanh toán từ năm 2013. Công ty đã nhận tạm ứng trước tổng cộng 196.9 tỷ đồng từ các cá nhân (ông Nguyễn Sơn Thạch 103 tỷ, ông Lê Trung Hiền 47 tỷ, ông Nguyễn Hồng Sơn 46.9 tỷ) để bán nợ phải thu, tuy nhiên chưa ký kết hợp đồng mua bán nợ chính thức, tiềm ẩn rủi ro pháp lý và thiếu minh bạch. Ngoài ra, nhận thêm 3.7 tỷ từ cán bộ nhân viên cũ để đảm bảo nghĩa vụ phối hợp giải quyết công nợ khó đòi. Các khoản phải thu từ khách hàng (tổng hơn 231 tỷ) đã toàn bộ quá hạn trên 3 năm với dự phòng 100%, phản ánh chất lượng tài sản rất kém.', 'Áp lực nợ vay rất nghiêm trọng: nợ ngắn hạn vượt tài sản ngắn hạn khoảng 226,444 tỷ đồng. Công ty phải dựa vào vay cá nhân (nhân viên và cá nhân bên ngoài) với lãi suất 7%/năm để bổ sung vốn hoạt động và thanh toán nghĩa vụ thuế. Khoản vay từ Tổng công ty May Hưng Yên đã quá hạn hơn 10 năm chưa được xử lý. Vốn chủ sở hữu âm 223,314 tỷ đồng cho thấy doanh nghiệp hoạt động hoàn toàn dựa vào nợ, không còn khả năng tự chủ tài chính. Trong năm 2024, Công ty đã tất toán khoản vay dài hạn 8.05 tỷ với Công ty CP Nhất Long và được điều chỉnh giảm lãi vay 207 triệu.', 'Hàng tồn kho giá gốc 53.8 triệu đồng đã trích lập dự phòng giảm giá 100%, giá trị sổ sách còn lại bằng 0. Rủi ro tồn kho thấp do số lượng không đáng kể, tuy nhiên phản ánh doanh nghiệp không còn hoạt động sản xuất kinh doanh hàng hóa vật tư, hoạt động chính chuyển sang cho thuê tài sản.', 8, 'Doanh nghiệp trong tình trạng tài chính nghiêm trọng: lỗ lũy kế 268 tỷ đồng, vốn chủ sở hữu âm 223 tỷ đồng, nợ ngắn hạn vượt tài sản ngắn hạn 226 tỷ đồng. Kiểm toán viên đưa ra ý kiến ngoại trừ (khoản phải trả người bán 1.4 tỷ không có biên bản đối chiếu) và nhấn mạnh về giả định hoạt động liên tục. Doanh thu 2024 chỉ 4.87 tỷ (chủ yếu từ cho thuê tài sản), giảm mạnh so với 9.25 tỷ năm 2023. Lợi nhuận sau thuế 3.4 tỷ chủ yếu nhờ hoàn nhập dự phòng phải thu khó đòi 3.3 tỷ, không phải từ hoạt động kinh doanh cốt lõi. Công ty đang trong quá trình tái cấu trúc tài chính với kế hoạch bán nợ phải thu cho các cá nhân nhưng chưa hoàn tất. Lỗ lũy kế đã giảm từ 271.4 tỷ xuống 268 tỷ nhưng mức âm vốn chủ sở hữu vẫn rất lớn. Triển vọng đầu tư cực kỳ rủi ro, phụ thuộc hoàn toàn vào thành công của tái cấu trúc và sự hỗ trợ từ Tập đoàn Dệt may Việt Nam.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VTI_2022_consolidated', 'VTI', 2022, 'consolidated', 'Doanh nghiệp có nhiều giao dịch và số dư với bên liên quan, đặc biệt là Tập đoàn Dệt may Việt Nam (công ty mẹ), bao gồm cho vay và phải trả, cho thấy sự phụ thuộc lớn vào công ty mẹ.', 'Công ty có nợ vay ngắn hạn vượt quá tài sản ngắn hạn, các khoản nợ đều quá hạn thanh toán hoặc đến hạn, tài sản thế chấp chủ yếu là bất động sản và cổ phần, áp lực nợ vay rất cao.', 'Hàng tồn kho thấp và đã trích lập dự phòng đầy đủ, không có rủi ro tồn kho đáng kể.', 8, 'Công ty đang trong tình trạng tài chính khó khăn với lỗ lũy kế lớn, vốn chủ sở hữu âm, và phụ thuộc vào sự hỗ trợ từ công ty mẹ. Khả năng thanh toán ngắn hạn kém, rủi ro đầu tư cao.'),
('VTI_2021_consolidated', 'VTI', 2021, 'consolidated', 'Công ty có nhiều giao dịch với bên liên quan, đặc biệt là công ty mẹ Tập đoàn Dệt May Việt Nam và các công ty con. Các khoản vay từ công ty mẹ chủ yếu với lãi suất 0% và được bảo lãnh, cho thấy sự hỗ trợ tài chính lớn. Các khoản phải trả người bán với công ty con Đông Xuân cũng đáng kể. Tuy nhiên, không có dấu hiệu giao dịch bất thường rõ ràng.', 'Rủi ro nợ vay rất cao. Công ty có nợ ngắn hạn vượt tài sản ngắn hạn 268,724 triệu VND, tổng nợ phải trả vượt tổng tài sản 271,288 triệu VND. Có nhiều khoản vay đã quá hạn trị giá 182,131 triệu VND từ các ngân hàng và tổ chức khác. Khả năng thanh toán phụ thuộc hoàn toàn vào sự hỗ trợ tài chính của công ty mẹ.', 'Rủi ro tồn kho thấp. Hàng tồn kho có giá trị ghi sổ 53,766,439 VND nhưng đã được trích lập dự phòng giảm giá toàn bộ. Không có hàng tồn kho dở dang hay dự án xây dựng dở dang.', 7, 'Công ty hoạt động trong ngành dệt may, với doanh thu ổn định nhưng lợi nhuận gộp biên thấp (~11.5%). Công ty đang trong tình trạng tài chính rất khó khăn với lỗ lũy kế lớn (-316,015 triệu VND), nợ ngắn hạn vượt tài sản ngắn hạn và nhiều khoản vay quá hạn. Khả năng hoạt động liên tục phụ thuộc vào sự hỗ trợ từ công ty mẹ. Ý kiến kiểm toán ngoại trừ do vấn đề chi phí lãi vay và các khoản phải trả không được xác nhận. Triển vọng đầu tư tiêu cực do rủi ro tài chính cao.'),
('VTI_2020_consolidated', 'VTI', 2020, 'consolidated', 'Công ty có giao dịch với các bên liên quan bao gồm công ty mẹ, công ty con và công ty liên kết, với các khoản phải trả và phải thu thương mại. Không có bằng chứng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn, nhưng sự phụ thuộc vào công ty mẹ về tài trợ và bảo lãnh là đáng chú ý.', 'Áp lực nợ vay rất cao với nợ ngắn hạn vượt quá tài sản ngắn hạn 263.908 triệu VND và tổng nợ phải trả vượt quá tổng tài sản 262.727 triệu VND. Có khoản vay đáng kể đã quá hạn 186.091 triệu VND, và công ty cần tái trợ tài chính trong 12 tháng tới. Nhiều khoản vay không lãi suất nhưng có tài sản thế chấp hoặc bảo lãnh từ công ty mẹ.', 'Rủi ro tồn kho thấp vì hàng tồn kho có giá trị 53,766,439 VND nhưng đã lập dự phòng giảm giá toàn bộ, nên giá trị sổ sách là 0. Không có dự án xây dựng dở dang.', 7, 'Công ty đang đối mặt với khó khăn tài chính nghiêm trọng với nợ vượt quá tài sản và lỗ lũy kế lớn. Tuy nhiên, công ty nhận được sự hỗ trợ từ công ty mẹ, Tập đoàn Dệt may Việt Nam, về tài chính và bảo lãnh. Triển vọng đầu tư rủi ro cao do phụ thuộc vào công ty mẹ và khả năng thanh toán nợ hạn chế.'),
('VTI_2019_consolidated', 'VTI', 2019, 'consolidated', 'Công ty có nhiều giao dịch với bên liên quan, đặc biệt là Tập đoàn Dệt may Việt Nam (công ty mẹ), bao gồm các khoản vay không lãi suất và khoản phải trả không lãi suất. Các khoản phải thu từ công ty con/công ty liên kết đã được lập dự phòng 100%, cho thấy rủi ro thu hồi cao.', 'Áp lực nợ vay cực kỳ cao với tổng nợ phải trả vượt tổng tài sản 262.746 triệu VND. Nhiều khoản vay đã quá hạn (189.123 triệu VND). Công ty phụ thuộc vào sự hỗ trợ tài chính từ công ty mẹ để thanh toán các khoản nợ đến hạn.', 'Hàng tồn kho rất thấp và đã được dự phòng giảm giá đầy đủ, không có rủi ro tồn kho đáng kể.', 8, 'Công ty đang trong tình trạng tài chính rất khó khăn: lỗ lũy kế lớn (307.473 triệu VND), nợ phải trả vượt tổng tài sản, nhiều khoản vay quá hạn. Khả năng tiếp tục hoạt động phụ thuộc hoàn toàn vào sự hỗ trợ tài chính từ công ty mẹ. Triển vọng đầu tư không rõ ràng và rủi ro rất cao.'),
('VTI_2018_consolidated', 'VTI', 2018, 'consolidated', 'Công ty có quan hệ tài chính phức tạp với công ty mẹ Tập đoàn Dệt May Việt Nam và các công ty con/công ty liên kết của tập đoàn. Công ty nhận vay từ công ty mẹ không lãi suất (gần 79 tỷ VND) và nợ phải trả không lãi suất (3,36 tỷ VND). Đồng thời, công ty có khoản phải thu lớn từ khách hàng là bên liên quan (Công ty Cổ phần Dệt Vĩnh Phú) và khoản phải trả cho Công ty TNHH Dệt kim Đông Xuân (công ty con của công ty mẹ) gần 5,4 tỷ VND. Các giao dịch được áp dụng điều khoản thương mại tương tự bên thứ ba. Công ty phụ thuộc hoàn toàn vào hỗ trợ tài chính từ công ty mẹ để duy trì hoạt động.', 'Áp lực nợ vay cực kỳ nghiêm trọng. Tổng nợ vay lên tới 405 tỷ VND trong khi tổng tài sản chỉ 19,4 tỷ VND, tỷ lệ nợ/tài sản vượt 20 lần. Nợ ngắn hạn 209 tỷ VND lớn gấp nhiều lần tài sản ngắn hạn (15 tỷ VND). Toàn bộ khoản vay dài hạn (196 tỷ VND) sẽ đáo hạn trong 12 tháng tới, tạo áp lực tái tài trợ lớn. Chi phí lãi vay năm 2018 là 10,2 tỷ VND, vượt xa lợi nhuận gộp 3,3 tỷ VND. Tất cả các khoản vay đều được bảo lãnh bởi công ty mẹ.', 'Rủi ro tồn kho thấp do hàng tồn kho còn rất nhỏ (53,8 triệu VND) và đã được trích lập dự phòng giảm giá toàn bộ. Công ty không có dự án xây dựng dở dang hay hàng hóa dở dang trên bảng cân đối kế toán.', 7, 'Công ty trong tình trạng tài chính nghiêm trọng: vốn chủ sở hữu âm 262,7 tỷ VND, lỗ lũy kế 307,5 tỷ VND, nợ ngắn hạn vượt tài sản ngắn hạn 264 tỷ VND. Công ty liên tục lỗ nặng (2017: -49,2 tỷ, 2018: -16,6 tỷ), doanh thu sụt giảm 45% từ 56,7 tỷ xuống 30,9 tỷ VND. Lợi nhuận gộp 3,3 tỷ VND không đủ bù chi phí lãi vay 10,2 tỷ VND. Hơn 193 tỷ VND nợ dài hạn sẽ đáo hạn trong 12 tháng tới. Toàn bộ hoạt động và khả năng thanh toán phụ thuộc vào công ty mẹ Tập đoàn Dệt May Việt Nam. Nếu công ty mẹ ngừng hỗ trợ, doanh nghiệp sẽ mất khả năng thanh toán.'),
('VTI_2016_consolidated', 'VTI', 2016, 'consolidated', 'Công ty có giao dịch đáng kể với công ty mẹ và các công ty liên kết, nhưng do công ty đang thua lỗ, có thể có rủi ro về phụ thuộc tài chính hoặc giao dịch không theo giá thị trường.', 'Nợ phải trả vượt quá tổng tài sản, nợ ngắn hạn vượt tài sản ngắn hạn, áp lực nợ vay cao với các khoản vay lớn cần tái tài trợ. Khả năng thanh toán thấp, tài sản thế chấp chủ yếu là bảo lãnh từ công ty mẹ.', 'Hàng tồn kho nhỏ và đã lập dự phòng giảm giá toàn bộ, rủi ro tồn kho thấp.', 8, 'Công ty đang trong tình trạng tài chính khó khăn với lỗ lũy kế lớn, nợ phải trả vượt quá tài sản, và khả năng tiếp tục hoạt động phụ thuộc vào hỗ trợ từ công ty mẹ và tái tài trợ. Triển vọng đầu tư tiêu cực.'),
('VTH_2025_consolidated', 'VTH', 2025, 'consolidated', 'Công ty có giao dịch đáng kể với Công ty Cổ phần Tập đoàn Đức Tường (bên liên quan đến ngày 25/04/2025): doanh thu bán hàng 16,8 tỷ VND, mua hàng hóa/vật tư gần 960 triệu VND, thuê xưởng 1,275 tỷ VND. Năm trước, Đức Tường là khách hàng lớn với doanh thu 161,6 tỷ VND. Đầu năm, phải thu Đức Tường là 9,16 tỷ VND (đã thu hồi hết trong năm). Công ty có các khoản tạm ứng và cho vay cá nhân liên quan đến thành viên quản lý (15 tỷ VND tạm ứng và 4,8 tỷ VND mượn tiền năm trước - đã xử lý trong năm nay). Giá giao dịch với bên liên quan là giá thỏa thuận, không có bằng chứng rõ ràng về giao dịch bất thường nghiêm trọng.', 'Tổng nợ vay và nợ thuê tài chính là 512 tỷ VND (nợ ngắn hạn 351,5 tỷ, nợ dài hạn 160,5 tỷ), tăng mạnh so với đầu năm (283,6 tỷ). Tỷ lệ nợ/vốn chủ sở hữu khoảng 4,7 lần, cho thấy đòn bẩy tài chính cao. Nợ vay tăng chủ yếu do đầu tư tài sản cố định lớn (nguyên giá TSCĐ hữu hình tăng từ 144 tỷ lên 267 tỷ VND) và bổ sung vốn lưu động. Công ty vay từ 6 ngân hàng khác nhau với lãi suất quy định theo từng lần nhận nợ. Toàn bộ khoản vay ngắn hạn được đảm bảo bằng hàng tồn kho, tiền gửi có kỳ hạn, quyền đòi nợ và bất động sản cá nhân của ban lãnh đạo (bảo lãnh cá nhân). Không có khoản vay quá hạn. Công ty có khả năng trả được các khoản vay theo thuyết minh.', 'Tổng hàng tồn kho giảm từ 235,2 tỷ xuống 195,3 tỷ VND, trong đó nguyên liệu giảm mạnh từ 118,5 tỷ xuống 59 tỷ VND, thành phẩm tăng từ 77,1 tỷ lên 103 tỷ VND. Không có dự phòng giảm giá hàng tồn kho. Chi phí sản xuất kinh doanh dở dang giảm nhẹ từ 25,7 tỷ xuống 20,8 tỷ VND. Chi phí xây dựng cơ bản dở dang giảm từ 23,4 tỷ xuống 18,9 tỷ VND do kết chuyển thành công vào tài sản cố định. Hàng tồn kho là tài sản thế chấp cho nhiều khoản vay ngân hàng. Rủi ro tồn kho ở mức trung bình, không có dấu hiệu ứ đọng nghiêm trọng.', 4, 'Công ty Cổ phần Dây cáp điện Việt Thái ghi nhận kết quả kinh doanh tích cực trong năm 2025: doanh thu thuần tăng 49,8% lên 1.134 tỷ VND, lợi nhuận sau thuế tăng 31,6% lên 12,1 tỷ VND. Biên lợi nhuận gộp giảm từ 9,63% xuống 7,66% do chi phí nguyên liệu tăng mạnh. Công ty thực hiện đầu tư mở rộng sản xuất lớn với tổng tài sản tăng 51% lên 768,5 tỷ VND. Đòn bẩy tài chính cao (nợ/vốn chủ sở hữu ~4,7 lần) nhưng được hỗ trợ bởi dòng tiền hoạt động kinh doanh dương 24,7 tỷ VND và toàn bộ khoản vay có tài sản đảm bảo. Giao dịch bên liên quan với Đức Tường Group đã giảm đáng kể trong năm 2025. Công ty đã phát hành riêng lẻ 3 triệu cổ phiếu để trả nợ ngân hàng. Rủi ro chính là áp lực trả nợ vay lớn trong bối cảnh biên lợi nhuận gộp co lại và phụ thuộc lớn vào tài sản thế chấp.'),
('VTH_2024_consolidated', 'VTH', 2024, 'consolidated', 'Công ty có giao dịch lớn với Công ty Cổ phần Tập đoàn Đức Tường - bên liên quan có cùng thành viên chủ chốt. Doanh thu bán hàng cho Tập đoàn Đức Tường và các chi nhánh đạt 161.649.980.376 VND (chiếm khoảng 21% tổng doanh thu), tăng mạnh so với năm trước (101.278.937.963 VND). Ngoài ra còn có giao dịch mua hàng hóa (6.265.303.526 VND), mua vật tư (4.729.012.079 VND), chi phí thuê xưởng (4.860.000.000 VND) và các giao dịch tài chính khác. Công ty cũng có khoản tạm ứng cho các thành viên quản lý chủ chốt lên tới 15.005.524.001 VND và cho mượn tiền 4.845.192.000 VND. Các khoản phải thu từ Đức Tường cuối năm 9.159.710.830 VND. Mức độ tập trung giao dịch với một bên liên quan là đáng lưu ý.', 'Tổng nợ vay và nợ thuê tài chính ngắn hạn là 261.132.449.313 VND, dài hạn 22.493.362.269 VND (tổng cộng ~283,6 tỷ VND). Tỷ lệ nợ vay trên vốn chủ sở hữu xấp xỉ 2,9:1, cho thấy đòn bẩy tài chính cao. Lãi vay trong năm là 15.452.427.989 VND, lớn hơn nhiều so với lợi nhuận sau thuế (9.215.906.017 VND). Hầu hết các khoản vay đều có tài sản thế chấp là hàng tồn kho, phải thu khách hàng, tiền gửi có kỳ hạn, tài sản cố định và bảo lãnh cá nhân của ban lãnh đạo. Công ty không có nợ quá hạn thanh toán.', 'Hàng tồn kho tăng mạnh từ 157.641.886.372 VND lên 235.196.798.172 VND (tăng 49%). Trong đó nguyên liệu tăng từ 45,9 tỷ lên 118,5 tỷ VND, thành phẩm tăng từ 47,4 tỷ lên 77,1 tỷ VND. Hàng hóa giảm từ 32,0 tỷ xuống 13,3 tỷ VND. Chi phí xây dựng cơ bản dở dang là 23,4 tỷ VND. Toàn bộ hàng tồn kho đã được thế chấp cho các khoản vay ngân hàng. Giá vốn hàng bán chiếm tỷ trọng lớn trong doanh thu (~90,4%), biên lợi nhuận gộp mỏng. Không có dự phòng giảm giá hàng tồn kho.', 6, 'Công ty Dây cáp điện Việt Thái có doanh thu tăng trưởng mạnh 49,7% đạt 762,8 tỷ VND, lợi nhuận sau thuế đạt 9,2 tỷ VND (tăng 38,9%). Tuy nhiên, biên lợi nhuận gộp còn mỏng (~9,6%), chi phí lãi vay rất lớn (15,4 tỷ VND) gần bằng gấp đôi lợi nhuận ròng. Công ty phụ thuộc lớn vào vay nợ ngắn hạn và giao dịch với bên liên quan Tập đoàn Đức Tường (~21% doanh thu). Hàng tồn kho tăng mạnh 49% cần được giám sát. Ban lãnh đạo có thay đổi lớn trong năm 2024 với nhiều vị trí chủ chốt được bổ nhiệm lại. Công ty có tài sản thế chấp đầy đủ cho các khoản vay và không có nợ quá hạn.'),
('VTH_2023_consolidated', 'VTH', 2023, 'consolidated', 'Công ty có nhiều giao dịch với bên liên quan, đặc biệt với Công ty Cổ phần Tập đoàn Đức Tường (bán hàng, mua hàng, thuê xưởng, cho mượn tiền). Các khoản cho vay không tính lãi suất cho cá nhân (Ông Đặng Văn Trường, Ông Nguyễn Đức Khang) và công ty liên quan. Tuy nhiên, giá giao dịch được cho là theo giá thỏa thuận.', 'Nợ vay tăng mạnh từ 159.560 tỷ VNĐ lên 262.519 tỷ VNĐ, chiếm tỷ trọng lớn trong tổng nguồn vốn. Nợ ngắn hạn (245.393 tỷ) cao hơn nợ dài hạn (17.125 tỷ), tạo áp lực trả nợ trong ngắn hạn. Tài sản thế chấp chủ yếu là hàng tồn kho, phải thu và tài sản cố định. Công ty cam kết có khả năng trả nợ.', 'Hàng tồn kho tăng mạnh từ 88.306 tỷ lên 157.642 tỷ VNĐ, chủ yếu do tăng nguyên vật liệu và thành phẩm. Chi phí sản xuất dở dang cũng tăng. Rủi ro ứ đọng tồn kho nếu hoạt động tiêu thụ chậm lại.', 5, 'Công ty tăng trưởng mạnh về doanh thu và lợi nhuận sau thuế (tăng 22% và 152% so với năm trước). Tuy nhiên, nợ vay và hàng tồn kho tăng nhanh, tiềm ẩn rủi ro thanh khoản và quản lý vốn lưu động. Công ty có nhiều giao dịch với bên liên quan nhưng chưa phát hiện giao dịch bất thường nghiêm trọng. Điểm rủi ro quản trị ở mức trung bình.'),
('VTH_2021_consolidated', 'VTH', 2021, 'consolidated', 'Công ty có giao dịch mua bán lớn với Công ty Cổ phần Tập đoàn Đức Tường (bên liên quan - công ty cùng thành viên chủ chốt), bao gồm doanh thu bán thành phẩm 72,8 tỷ VNĐ và mua hàng hóa 25,6 tỷ VNĐ trong năm. Giá giao dịch theo thỏa thuận. Có khoản phải thu 5,6 tỷ VNĐ và phải trả 5,6 tỷ VNĐ với bên này. Công ty cũng cho ông Đăng Văn Trường (cổ đông) mượn 800 triệu VNĐ không rõ lãi suất. Các cá nhân trong ban lãnh đạo đã dùng tài sản cá nhân (đất đai, cổ phiếu) để bảo lãnh cho khoản vay của công ty, cho thấy sự gắn kết tài chính chặt chẽ giữa công ty và cổ đông lớn.', 'Tổng nợ vay ngắn hạn khoảng 73 tỷ VNĐ và nợ dài hạn khoảng 3,75 tỷ VNĐ. Công ty chủ yếu vay từ Ngân hàng TMCP Sài Gòn Thương tín và nhiều ngân hàng khác. Các khoản vay được đảm bảo bằng tài sản cố định, hàng tồn kho, phải thu và cả cổ phiếu của cổ đông. Chi phí lãi vay năm nay tăng mạnh lên 4,5 tỷ VNĐ so với 3 tỷ VNĐ năm trước. Công ty cam kết trả được các khoản vay, tuy nhiên áp lực nợ vay ngắn hạn đáng kể khi chiếm tỷ trọng lớn trong tổng nợ.', 'Hàng tồn kho tăng mạnh từ 44 tỷ lên 57,7 tỷ VNĐ, chủ yếu do tăng thành phẩm và nguyên liệu. Không có dự phòng giảm giá hàng tồn kho nào được trích lập. Chi phí sản xuất dở dang chiếm 13,3 tỷ VNĐ. Hàng tồn kho toàn bộ đã được thế chấp cho khoản vay ngân hàng. Rủi ro tồn kho ở mức trung bình khi doanh thu tăng tương ứng nhưng cần theo dõi khả năng tiêu thụ.', 5, 'Công ty Dây cáp điện Việt Thái có bước cải thiện vượt bậc về kết quả kinh doanh năm 2021 với lợi nhuận sau thuế 4,25 tỷ VNĐ (so với 89 triệu năm trước), doanh thu thuần tăng 32%. Tuy nhiên, công ty có giao dịch lớn với bên liên quan Tập đoàn Đức Tường, nợ vay chiếm tỷ trọng cao trong tổng tài sản, và hàng tồn kho tăng mạnh không có dự phòng. Khả năng sinh lời cải thiện rõ rệt nhưng dòng tiền hoạt động kinh doanh âm 9,8 tỷ VNĐ do tăng vốn lưu động. Công ty có nền tảng sản xuất tốt nhưng cần quản lý tốt hơn quan hệ với bên liên quan và kiểm soát hàng tồn kho.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VTH_2022_consolidated', 'VTH', 2022, 'consolidated', 'Doanh nghiệp có giao dịch đáng kể với bên liên quan, bao gồm bán hàng, mua hàng và cho vay tiền. Cụ thể, doanh thu bán thành phẩm cho Công ty Cổ phần Tập đoàn Đức Tường chiếm tỷ trọng lớn, mua hàng hóa từ cùng công ty này, và cho mượn tiền cho cổ đông lớn Ông Đăng Văn Trường. Các giao dịch này có thể không được thực hiện trên cơ sở giá thị trường, tạo rủi ro về lợi ích và dòng tiền. Ngoài ra, Công ty vay tiền từ cá nhân liên quan đến ban lãnh đạo với lãi suất thấp hơn thị trường.', 'Nợ vay ngắn hạn tăng mạnh từ 72.9 tỷ lên 104.8 tỷ VNĐ, với phần lớn được thế chấp bằng tài sản của công ty và cổ phiếu của cổ đông lớn. Nợ dài hạn cũng tăng từ 3.7 tỷ lên 8.3 tỷ VNĐ. Áp lực trả nợ cao do nợ ngắn hạn chiếm phần lớn, nhưng công ty tuyên bố có khả năng thanh toán. Tuy nhiên, tài sản thế chấp chủ yếu từ bên liên quan có thể gây rủi ro nếu kinh doanh suy giảm.', 'Hàng tồn kho tăng từ 57.6 tỷ lên 88.3 tỷ VNĐ, bao gồm nguyên liệu, thành phẩm và chi phí sản xuất dở dang. Không có dự phòng giảm giá hàng tồn kho, điều này có thể rủi ro nếu giá nguyên liệu biến động hoặc nhu cầu giảm. Dự án xây dựng cơ bản dở dang (13.5 tỷ VNĐ) cũng tăng, cần giám sát tiến độ và hiệu quả đầu tư.', 7, 'Doanh thu tăng trưởng mạnh nhưng lợi nhuận giảm do chi phí bán hàng và quản lý tăng cao. Nợ vay tăng đáng kể, chủ yếu là ngắn hạn, với tài sản thế chấp từ bên liên quan. Hàng tồn kho tăng nhanh, có thể ảnh hưởng đến dòng tiền. Quản trị có rủi ro do giao dịch bên liên quan phức tạp. Triển vọng phụ thuộc vào khả năng kiểm soát chi phí và quản lý tồn kho hiệu quả.'),
('VTH_2020_consolidated', 'VTH', 2020, 'consolidated', 'Công ty có giao dịch mua bán hàng hóa với Công ty CP tập đoàn Đức Tường (cùng thành viên góp vốn) với giá trị lớn, đồng thời cho vay không lãi suất từ các thành viên Hội đồng Quản trị (ông Nguyễn Đức Tường, ông Phan Hoàng Tuấn) và cá nhân liên quan. Điều này tiềm ẩn rủi ro giao dịch không theo giá thị trường và xung đột lợi ích.', 'Tổng nợ vay tăng mạnh từ 31.890 tỷ đồng lên 55.146 tỷ đồng, chủ yếu là nợ ngắn hạn, tạo áp lực thanh khoản lớn. Tài sản thế chấp bao gồm tiền gửi ngân hàng bị phong tỏa và tài sản cố định. Công ty phụ thuộc nhiều vào nguồn vốn vay ngân hàng.', 'Hàng tồn kho tăng từ 36.700 tỷ đồng lên 43.959 tỷ đồng, đặc biệt nguyên liệu tăng gấp đôi. Dự phòng giảm giá hàng tồn kho đã được hoàn nhập toàn bộ trong năm, cho thấy rủi ro tồn kho thấp nhưng cần theo dõi xu hướng tích trữ nguyên liệu.', 6, 'Công ty có doanh thu tăng nhẹ 6% nhưng lợi nhuận sau thuế giảm mạnh 98% do chi phí tài chính và bán hàng tăng cao. Nợ vay tăng đột biến gây áp lực thanh khoản, dòng tiền hoạt động kinh doanh âm. Ban lãnh đạo có nhiều thay đổi trong năm. Rủi ro quản trị ở mức trung bình do có giao dịch với bên liên quan và cho vay không lãi suất. Triển vọng kinh doanh phụ thuộc vào khả năng quản lý nợ và tối ưu hóa chi phí.'),
('VTH_2019_consolidated', 'VTH', 2019, 'consolidated', 'Công ty có giao dịch mua bán với các bên liên quan (Tập đoàn Đức Tường, Phát triển Mạnh Khang) với giá trị lớn, tuy nhiên được thực hiện theo giá thị trường. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay tăng mạnh từ 30.4 tỷ lên 43.7 tỷ VND, áp lực trả nợ cao. Công ty có tài sản thế chấp (nhà xưởng, tài sản cố định) và cho biết có khả năng trả nợ từ dòng tiền kinh doanh và tiếp cận nguồn vốn.', 'Hàng tồn kho giảm từ 45.5 tỷ xuống 37.0 tỷ VND, dự phòng giảm giá tồn kho giảm. Thành phẩm ứ đọng giảm mạnh từ 2.7 tỷ xuống 47 triệu VND. Có chi phí xây dựng dở dang nhỏ 25 triệu VND.', 6, 'Công ty lỗ nặng năm 2018 nhưng đã có lãi trở lại năm 2019. Doanh thu giảm đáng kể nhưng biên lợi nhuận gộp cải thiện mạnh. Nợ vay tăng cao, cần giám sát khả năng thanh toán. Giao dịch bên liên quan có giá trị lớn nhưng theo giá thị trường. Nhân sự cấp cao biến động nhiều trong năm. Triển vọng tích cực trong ngắn hạn nhưng cần quản lý rủi ro nợ và chuỗi cung ứng.'),
('VTH_2018_consolidated', 'VTH', 2018, 'consolidated', 'Rủi ro thấp. Giao dịch với bên liên quan chủ yếu là chi trả cổ tức cho cổ đông lớn và lương thưởng cho ban lãnh đạo, không có giao dịch bán hàng bất thường hay cho vay không lãi suất.', 'Rủi ro cao. Công ty có nợ vay ngắn hạn với tổng số tiền 16,85 tỷ VNĐ, đáo hạn trong 12 tháng, được thế chấp bằng tài sản cố định. Công ty lỗ ròng năm 2018, dòng tiền từ hoạt động kinh doanh dương nhưng áp lực trả nợ lớn, phụ thuộc vào việc gia hạn hoặc vay mới.', 'Rủi ro trung bình. Hàng tồn kho giảm so với đầu năm, nhưng có trích lập dự phòng giảm giá hàng tồn kho 3,03 tỷ VNĐ cho thành phẩm, cho thấy một phần tồn kho ứ đọng. Công ty cần quản lý tốt chu kỳ tồn kho để tránh ảnh hưởng dòng tiền.', 5, 'Công ty Dây cáp điện Việt Thái hoạt động trong ngành sản xuất và thương mại dây cáp điện. Năm 2018, doanh thu giảm mạnh 21,5% so với năm trước, chủ yếu do doanh thu bán hàng hóa giảm. Giá vốn hàng bán tăng do chi phí nguyên vật liệu tăng, dẫn đến lợi nhuận gộp sụt giảm và lỗ ròng sau thuế 7,33 tỷ VNĐ. Nợ vay ngắn hạn ở mức cao, tài sản cố định đã được thế chấp, gây áp lực thanh khoản. Công ty đã trích lập dự phòng giảm giá hàng tồn kho, phản ánh rủi ro hàng hóa tồn đọng. Quản trị doanh nghiệp có biến động lớn với nhiều thay đổi nhân sự cấp cao, nhưng không có giao dịch với bên liên quan bất thường. Triển vọng ngắn hạn khó khăn do thua lỗ và áp lực nợ, cần cải thiện hiệu quả kinh doanh và quản lý dòng tiền.'),
('VTH_2017_consolidated', 'VTH', 2017, 'consolidated', 'Công ty chỉ có giao dịch trả cổ tức cho cổ đông lớn, không phát sinh giao dịch mua bán hay cho vay với các bên liên quan.', 'Nợ vay ngắn hạn tăng mạnh từ 4 tỷ lên 16.6 tỷ, chủ yếu để bổ sung vốn lưu động, có tài sản thế chấp. Áp lực nợ vay ở mức trung bình, cần theo dõi khả năng trả nợ.', 'Hàng tồn kho tăng từ 41.9 tỷ lên 54.9 tỷ, không có dự phòng giảm giá, rủi ro tồn kho ở mức thấp.', 3, 'Công ty tăng trưởng doanh thu mạnh (93%) nhưng lợi nhuận giảm do giá nguyên liệu đầu vào tăng. Nợ vay ngắn hạn tăng đáng kể, dòng tiền từ hoạt động kinh doanh dương nhưng nhỏ. Triển vọng trung bình, cần cải thiện biên lợi nhuận.'),
('VTH_2016_consolidated', 'VTH', 2016, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là trả cổ tức cho cổ đông và bán hàng nhỏ lẻ, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay ngắn hạn, lãi suất thấp, không có tài sản đảm bảo, công ty có khả năng thanh toán tốt từ hoạt động kinh doanh.', 'Hàng tồn kho đa dạng, không có dự phòng giảm giá, tồn kho dở dang không đáng kể, rủi ro thấp.', 3, 'Công ty hoạt động trong ngành sản xuất dây cáp điện, doanh thu và lợi nhuận giảm so với năm trước do mất khách hàng lớn và giá nguyên liệu giảm. Tuy nhiên, tài sản ngắn hạn lớn hơn nợ ngắn hạn, khả năng thanh toán cao, rủi ro thấp.'),
('VTG_2025_consolidated', 'VTG', 2025, 'consolidated', 'Công ty có giao dịch với bên liên quan là Công ty cổ phần Giải trí Thể thao Minh Đạm, nhưng số dư nhỏ và không phát sinh giao dịch trong năm. Rủi ro thấp.', 'Khoản vay dài hạn từ ngân hàng đã được khoanh nợ, không áp lực thanh toán trong ngắn hạn. Tuy nhiên, công ty có nợ thuê đất chưa ghi nhận lớn (225 tỷ VND), có thể tạo áp lực tài chính và rủi ro pháp lý.', 'Tồn kho chủ yếu là nguyên liệu và hàng hóa, giá trị không đáng kể (dưới 1 tỷ VND), không có dấu hiệu ứ đọng hay rủi ro giảm giá.', 8, 'Tập đoàn hoạt động trong lĩnh vực du lịch và khách sạn, nhưng đang gặp khó khăn tài chính nghiêm trọng với lỗ sau thuế năm 2025 và nợ thuế chưa ghi nhận lớn. Ý kiến kiểm toán từ chối do thiếu bằng chứng, cho thấy rủi ro quản trị cao. Công ty có khoản đầu tư vào nhiều công ty con/liên kết có hiệu quả thấp, cần cải thiện quản trị và xử lý các khoản nợ để ổn định tài chính.'),
('VTH_2015_consolidated', 'VTH', 2015, 'consolidated', 'Doanh nghiệp có giao dịch mua bán hàng hóa, nguyên vật liệu và trả cổ tức với các cổ đông lớn (bên liên quan). Giá cả theo thỏa thuận, không có biểu hiện bất thường rõ ràng, nhưng lưu ý khoản phải thu và phải trả lớn với cùng một bên liên quan (Công ty cổ phần dây cấp điện Việt Nam) có thể ảnh hưởng đến dòng tiền và tạo sự phụ thuộc.', 'Nợ vay chủ yếu là ngắn hạn, không có tài sản đảm bảo, lãi suất cố định 5.5%/năm. Công ty đã trả hết nợ vay ngắn hạn trong năm, áp lực nợ vay thấp. Không có nợ dài hạn.', 'Hàng tồn kho tăng 27.6% so với đầu năm, chủ yếu là nguyên vật liệu và thành phẩm. Không có dự phòng giảm giá hàng tồn kho. Cần theo dõi khả năng tiêu thụ và rủi ro giảm giá nguyên vật liệu biến động.', 3, 'Công ty hoạt động trong lĩnh vực sản xuất dây cáp điện, có doanh thu và lợi nhuận ổn định. Dòng tiền từ hoạt động kinh doanh dương mạnh. Tuy nhiên, doanh thu phụ thuộc vào một số khách hàng lớn là bên liên quan. Hàng tồn kho tăng cao cần được kiểm soát. Không có nợ vay dài hạn, tình hình tài chính an toàn.'),
('VTG_2024_consolidated', 'VTG', 2024, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là công ty liên kết Công ty cổ phần Giải trí Thể thao Minh Đạm với số dư phải thu và phải trả không lớn. Tuy nhiên, khoản đầu tư vào công ty liên kết này không được cung cấp báo cáo tài chính đầy đủ, tiềm ẩn rủi ro về thiếu minh bạch thông tin.', 'Nợ vay dài hạn 14.05 tỷ VND đã được khoanh nợ từ trước cổ phần hóa, không tạo áp lực thanh toán. Tuy nhiên, doanh nghiệp có khoản tiền thuê đất và cơ sở hạ tầng chưa ghi nhận lên đến 225.22 tỷ VND theo kết luận thanh tra, cùng với nợ thuế phải nộp lớn, có thể gây áp lực tài chính đáng kể trong tương lai.', 'Hàng tồn kho có giá trị nhỏ (gần 600 triệu VND) và không trích lập dự phòng giảm giá, cho thấy rủi ro tồn kho thấp.', 8, 'Doanh nghiệp có lỗ lũy kế lớn (gần 38.6 tỷ VND), năm 2024 báo lãi chủ yếu nhờ ghi nhận thu nhập lớn từ thanh lý, nhượng bán tài sản cố định (trên 25 tỷ VND). Tình hình tài chính không ổn định, tiềm ẩn nhiều rủi ro pháp lý nghiêm trọng liên quan đến tiền thuê đất, nghĩa vụ thuế và thiếu minh bạch trong báo cáo tài chính (ý kiến kiểm toán từ chối). Triển vọng đầu tư ở mức rủi ro rất cao.'),
('VTG_2023_consolidated', 'VTG', 2023, 'consolidated', 'Công ty có giao dịch cho vay không lãi suất (0%/năm) với cổ đông của công ty con, tiềm ẩn nguy cơ lợi ích giữa các bên liên quan.', 'Nợ vay dài hạn đã được khoanh nợ từ trước cổ phần hóa, áp lực trả nợ ngắn hạn không cao nhưng tài sản thuần giảm mạnh có thể ảnh hưởng đến khả năng thanh toán.', 'Hàng tồn kho chủ yếu là nguyên vật liệu và hàng hóa, mức dự phòng giảm giá không đáng kể, rủi ro tồn kho thấp.', 8, 'Doanh nghiệp đang gặp khó khăn nghiêm trọng: ý kiến kiểm toán từ chối do chưa ghi nhận khoản tiền thuê đất lớn (225 tỷ VNĐ), hoạt động kinh doanh thua lỗ năm 2023, tài sản thuần suy giảm. Đầu tư vào các đơn vị khác có dự phòng tăng, tiềm ẩn rủi ro tài chính. Triển vọng đầu tư không rõ ràng.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VTG_2022_consolidated', 'VTG', 2022, 'consolidated', 'Giao dịch với bên liên quan không có gì bất thường, số dư phải thu nhỏ và đã trích lập dự phòng.', 'Nợ vay dài hạn đã được khoanh nợ và không phát sinh chi phí lãi vay, áp lực nợ thấp.', 'Hàng tồn kho có giá trị nhỏ và không có dự phòng giảm giá, rủi ro thấp.', 8, 'Doanh nghiệp có lợi nhuận sau thuế dương năm 2022 nhưng báo cáo kiểm toán bị từ chối ý kiến do chưa ghi nhận đầy đủ tiền thuê đất và cơ sở hạ tầng. Điều này tạo ra rủi ro lớn cho nhà đầu tư.'),
('VTG_2020_consolidated', 'VTG', 2020, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là số dư phải thu/phải trả nhỏ, không có giao dịch bất thường lớn. Các khoản cho vay không lãi suất là cho cổ đông cá nhân, không phải bên liên quan theo định nghĩa.', 'Áp lực nợ vay thấp do khoản vay dài hạn đã được khoanh nợ. Tuy nhiên, công ty đang đối mặt với nghĩa vụ tiền thuê đất và hạ tầng lớn (hơn 213 tỷ VND) chưa ghi nhận vào báo cáo tài chính, có thể tạo ra rủi ro tài chính và ảnh hưởng nghiêm trọng đến lợi nhuận nếu bị truy thu.', 'Hàng tồn kho chủ yếu là hàng hóa, nguyên vật liệu thông thường với giá trị thấp và không có dự phòng. Không có dự án xây dựng dở dang hay bất động sản đầu tư, rủi ro tồn kho thấp.', 7, 'Công ty chịu ảnh hưởng nặng nề từ đại dịch Covid-19 với khoản lỗ lớn trong năm 2020. Tình hình tài chính khó khăn do lỗ lũy kế và nghĩa vụ thuế đất lớn chưa ghi nhận. Công ty có nhiều khoản đầu tư vào công ty con, liên kết nhưng không hợp nhất được báo cáo. Triển vọng phụ thuộc vào khả năng phục hồi của ngành du lịch và giải quyết tranh chấp về tiền thuê đất.'),
('VTG_2019_consolidated', 'VTG', 2019, 'consolidated', 'Có giao dịch cho vay cổ đông với lãi suất 0%, thời hạn linh hoạt. Các khoản phải thu từ công ty liên kết (Công ty cổ phần Giải trí Thế thao Minh Đạm) đã tồn tại nhiều năm và được trích lập dự phòng 100%. Giao dịch với công ty liên kết có thể không theo giá thị trường.', 'Nợ dài hạn duy nhất là khoản vay đã được khoanh nợ, không áp lực trả nợ ngắn hạn. Tuy nhiên, doanh nghiệp có nghĩa vụ nợ thuê đất chưa ghi nhận lên đến 175.8 tỷ đồng, tạo rủi ro tài chính lớn.', 'Hàng tồn kho có giá trị nhỏ (1.44 tỷ đồng) và không có dự phòng giảm giá, rủi ro thấp.', 9, 'Doanh nghiệp hoạt động trong lĩnh vực du lịch, dịch vụ với doanh thu giảm nhẹ so với năm trước. Tình hình tài chính bị ảnh hưởng nghiêm trọng bởi khoản nợ thuê đất chưa ghi nhận (175.8 tỷ đồng), khiến kiểm toán viên từ chối đưa ra ý kiến. Công ty có nhiều khoản đầu tư vào các công ty liên kết, góp vốn khác nhưng không xác định được giá trị hợp lý. Rủi ro quản trị cao do vấn đề nợ đất phức tạp và giao dịch bên liên quan.'),
('VTG_2021_consolidated', 'VTG', 2021, 'consolidated', 'Doanh nghiệp có các giao dịch với công ty liên kết (Công ty cổ phần Giải trí Thể thao Minh Đạm, Công ty cổ phần Đầu tư Khách sạn Biển Đông) bao gồm cho vay, ứng trước và phải trả thuế. Đặc biệt, có khoản cho vay cổ đông (ông Nguyễn Vũ Hưng, ông Đỗ Minh Đức) với lãi suất 0% và thời hạn tùy thuộc vào nhu cầu của Tập đoàn, tiềm ẩn rủi ro về quản trị và lợi ích cổ đông thiểu số.', 'Nợ vay dài hạn 14 tỷ VND từ Vietcombank đã được khoanh nợ (phát sinh trước cổ phần hóa), không tạo áp lực thanh toán ngắn hạn. Tuy nhiên, tổng nợ phải trả chiếm tỷ trọng lớn (61,5 tỷ VND nợ phải trả trên tổng nguồn vốn 205 tỷ), trong đó nợ thuế và phí phải nộp nhà nước chiếm phần lớn, tiềm ẩn rủi ro pháp lý và phạt chậm nộp.', 'Hàng tồn kho có giá trị nhỏ (954 triệu VND) và không trích lập dự phòng. Tồn kho chủ yếu là hàng hóa và nguyên vật liệu phục vụ dịch vụ du lịch, ít rủi ro ứ đọng do tính chất ngành.', 8, 'Tình hình tài chính của Tập đoàn đang gặp nhiều thách thức nghiêm trọng. Kiểm toán viên đã đưa ra ý kiến ''Từ chối đưa ra ý kiến'' do các khoản tiền thuê đất, cơ sở hạ tầng lớn chưa được ghi nhận (225 tỷ VND) và việc không hợp nhất được đầu tư vào công ty liên kết. Doanh nghiệp liên tục hoạt động trong lĩnh vực du lịch, khách sạn bị ảnh hưởng nặng nề bởi COVID-19, dẫn đến lỗ lũy kế lớn (63 tỷ VND). Các rủi ro pháp lý từ việc thu hồi đất và tranh chấp thuế là đáng kể. Điểm sáng duy nhất là nợ vay dài hạn đã được khoanh nợ và tài sản cố định còn giá trị.'),
('VTG_2018_consolidated', 'VTG', 2018, 'consolidated', 'Công ty cho vay hai cổ đông (Ông Nguyễn Vũ Hưng và Ông Đỗ Minh Đức) tổng cộng hơn 5 tỷ VNĐ với lãi suất 0% và không có tài sản đảm bảo, thời hạn thu hồi theo nhu cầu vốn đầu tư. Đây là giao dịch bất thường, tiềm ẩn rủi ro mất vốn. Ngoài ra, Công ty có khoản nợ phải thu lớn với Công ty CP Giải trí Thể thao Minh Đạm (công ty liên kết) mà dự án đã bị UBND tỉnh thu hồi đất, khả năng thu hồi thấp.', 'Tổng nợ vay khoảng 14.5 tỷ VNĐ, chủ yếu là vay dài hạn tại Vietcombank với tài sản thế chấp là khách sạn Sammy. Công ty có vị thế tiền mặt dương (tiền mặt 20.1 tỷ VNĐ > tổng nợ vay 14.5 tỷ VNĐ), nợ thuần âm (-5.6 tỷ VNĐ), cho thấy áp lực nợ vay không cao. Tuy nhiên, khoản vay khoanh nợ trước cổ phần hóa tại Vietcombank là rủi ro tiềm ẩn.', 'Tồn kho có giá trị nhỏ (1.4 tỷ VNĐ) so với tổng tài sản (237.6 tỷ VNĐ), bao gồm nguyên liệu, công cụ dụng cụ và hàng hóa. Không trích lập dự phòng giảm giá hàng tồn kho. Rủi ro tồn kho thấp do quy mô nhỏ và không có hàng tồn kho dở dang hoặc dự án bất động sản.', 7, 'Công ty Du lịch Bà Rịa - Vũng Tàu có năm 2018 phục hồi mạnh với lợi nhuận sau thuế 9.5 tỷ VNĐ sau khoản lỗ 5.8 tỷ VNĐ năm 2017. Tuy nhiên, công ty đối mặt với rủi ro lớn từ nghĩa vụ thuế đất và hạ tầng tại Bãi tắm Thùy Vân với tổng giá trị chưa hạch toán hơn 126 tỷ VNĐ theo kết luận thanh tra. Báo cáo kiểm toán bị từ chối ý kiến do không thu thập đủ bằng chứng về thuế đất và các khoản đầu tư. Công ty có khoản đầu tư lớn vào các công ty liên kết/góp vốn (hơn 73 tỷ VNĐ) với nhiều khoản đã trích lập dự phòng. Doanh thu giảm 9% so với năm trước do mảng lữ hành sụt giảm mạnh. Dòng tiền hoạt động kinh doanh dương 8.6 tỷ VNĐ cho thấy khả năng tạo tiền tốt.'),
('VTG_2016_consolidated', 'VTG', 2016, 'consolidated', 'Công ty có giao dịch với các công ty liên kết là Công ty cổ phần Đầu tư Khách sạn Biển Đông và Công ty cổ phần Giải trí Thể thao Minh Đạm. Các giao dịch chủ yếu là góp vốn và phải thu khách hàng với số tiền không lớn. Tuy nhiên, cả hai công ty liên kết này đều đang trong giai đoạn đầu tư xây dựng, chưa hoạt động kinh doanh, điều này tiềm ẩn rủi ro về khả năng thu hồi vốn đầu tư. Cần theo dõi chặt chẽ tình hình hoạt động của các công ty liên kết này.', 'Tổng nợ vay và nợ thuê tài chính tại ngày 31/12/2016 là 22.235.092.939 VND. Áp lực nợ ngắn hạn cao với 6.403.799.426 VND đến hạn trong vòng 1 năm. Công ty có khoản vay cá nhân ngắn hạn lãi suất cao (1%/tháng). Tài sản đảm bảo chính là khách sạn Sammy – Vũng Tàu cho khoản vay dài hạn tại Vietcombank. Công ty có các khoản cam kết góp vốn lớn chưa thực hiện (khoảng 23,9 tỷ VND), tạo thêm áp lực tài chính. Khả năng thanh toán nợ phụ thuộc vào dòng tiền hoạt động kinh doanh và khả năng huy động vốn.', 'Hàng tồn kho có giá trị 1.755.835.799 VND, không có dự phòng giảm giá. Hàng tồn kho chủ yếu là nguyên liệu, vật liệu và hàng hóa phục vụ kinh doanh dịch vụ du lịch, ăn uống. Rủi ro tồn kho thấp do tính chất lưu thông nhanh của ngành dịch vụ. Không có tồn kho dở dang hay dự án xây dựng dở dang lớn.', 6, 'Công ty đang trong giai đoạn khó khăn với lợi nhuận sau thuế lỗ 6,27 tỷ VND năm 2016. Kiểm toán viên đưa ra ý kiến ngoại trừ do vấn đề chưa ghi nhận chi phí thuê đất 17,97 tỷ VND và khoản truy thu thuế 3,93 tỷ VND. Ban lãnh đạo có sự thay đổi lớn sau ngày kết thúc năm tài chính. Nợ vay ở mức trung bình nhưng áp lực nợ ngắn hạn cao. Các khoản đầu tư vào công ty liên kết chưa mang lại hiệu quả. Công ty cần cải thiện hiệu quả kinh doanh, xử lý dứt điểm các vấn đề về thuế và thuê đất để ổn định tình hình tài chính.'),
('VTG_2015_consolidated', 'VTG', 2015, 'consolidated', 'Thấp. Tập đoàn có giao dịch và công nợ với các công ty liên kết (Công ty Cổ phần Đầu tư Khách sạn Biển Đông, Công ty Cổ phần Giải trí Thể thao Minh Đạm) nhưng giá trị không lớn và chủ yếu là góp vốn. Không phát sinh giao dịch mua bán hàng hóa/dịch vụ đáng kể với các bên liên quan. Không có giao dịch bất thường hay cho vay không lãi suất được công bố.', 'Trung bình. Tổng nợ vay là 25,012,293,513 VND, trong đó nợ vay dài hạn chiếm tỷ trọng lớn. Công ty có các khoản vay cá nhân lãi suất cao (1%/tháng) không có tài sản đảm bảo. Tuy nhiên, Ban Tổng Giám đốc đánh giá có khả năng thanh toán nợ và không có nợ quá hạn. Các khoản vay ngân hàng được đảm bảo bằng tài sản cố định.', 'Thấp. Hàng tồn kho chủ yếu là nguyên liệu, công cụ và hàng hóa thương mại với giá trị không lớn (1,563,392,547 VND). Không có dự phòng giảm giá hàng tồn kho. Các dự án xây dựng dở dang và bất động sản đầu tư đang trong quá trình triển khai, chưa có thông tin về việc bị ứ đọng hay chậm trễ nghiêm trọng.', 4, 'Công ty hoạt động trong lĩnh vực du lịch - dịch vụ, có mối quan hệ với các công ty con, công ty liên kết và cổ đông nhà nước. Kết quả kinh doanh năm 2015 tăng trưởng so với năm trước, lợi nhuận sau thuế đạt 4.285.970.007 VND. Cơ cấu tài sản lành mạnh, nợ phải trả được kiểm soát. Tuy nhiên, công ty có một số khoản phải thu khó đòi lớn, cam kết đầu tư vào các đơn vị khác còn cao, và có khoản vay cá nhân lãi suất cao. Công ty được kiểm toán viên đưa ra ý kiến chấp nhận toàn phần, không có vấn đề về hoạt động liên tục.'),
('VTG_2017_consolidated', 'VTG', 2017, 'consolidated', 'Công ty có các giao dịch với các công ty liên kết bao gồm góp vốn, ứng trước tiền góp vốn, phải thu khách hàng và phải trả khác. Các giao dịch này có quy mô nhỏ và không đáng kể, nhưng cần theo dõi khả năng thu hồi từ các khoản phải thu của công ty liên kết.', 'Công ty có nợ vay dài hạn với tài sản thế chấp là khách sạn Sammy. Tuy nhiên, công ty liên tục lỗ trong năm 2017, tạo áp lực lên khả năng trả nợ. Nợ ngắn hạn đã giảm so với năm trước, nhưng nợ dài hạn vẫn cao.', 'Tồn kho chủ yếu là nguyên vật liệu và hàng hóa, không có dự án xây dựng dở dang. Rủi ro tồn kho thấp.', 5, 'Tập đoàn hoạt động trong ngành du lịch và khách sạn, doanh thu ổn định nhưng chi phí cao dẫn đến lỗ. Nợ vay cao và tài sản thế chấp là khách sạn. Triển vọng phụ thuộc vào khả năng quản lý chi phí và tăng doanh thu trong tương lai.'),
('VTE_2024_consolidated', 'VTE', 2024, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là Tập đoàn Bưu chính Viễn thông Việt Nam và các công ty con, tập trung vào mua bán hàng hóa. Không có dấu hiệu bất thường rõ ràng như cho vay không lãi suất, nhưng mức độ tập trung cao vào nhóm liên quan này có thể tạo rủi ro phụ thuộc.', 'Nợ vay ngắn hạn chiếm tỷ trọng lớn (33,5 tỷ VND) và giảm so với đầu năm. Nợ được đảm bảo bằng hàng hóa và phải thu. Áp lực nợ ngắn hạn vẫn tồn tại nhưng Công ty có dòng tiền kinh doanh dương và tài sản lưu động đủ để trang trải.', 'Hàng tồn kho giảm từ 118,5 tỷ xuống 101,2 tỷ VND, trong đó Chi phí SXKD dở dang chiếm tỷ trọng đáng kể (22,9 tỷ). Không có dự phòng giảm giá tồn kho được trích lập, cho thấy rủi ro ứ đọng thấp, nhưng cần theo dõi tiến độ luân chuyển của hàng dở dang.', 6, 'Công ty đang trong giai đoạn tái cơ cấu khi doanh thu và lợi nhuận sụt giảm so với năm trước. Tuy nhiên, dòng tiền hoạt động kinh doanh cải thiện mạnh, nợ vay giảm, và quản trị dòng tiền chặt chẽ. Rủi ro chính nằm ở sự phụ thuộc vào nhóm khách hàng VNPT và hàng tồn kho dở dang. Triển vọng trung hạn phụ thuộc vào khả năng đa dạng hóa khách hàng và nâng cao hiệu quả sản xuất.'),
('VTE_2025_consolidated', 'VTE', 2025, 'consolidated', 'Công ty có quan hệ mật thiết với Tập đoàn Bưu chính Viễn thông Việt Nam (VNPT) - cổ đông lớn sở hữu 32% vốn. Giao dịch mua bán với bên liên quan chiếm tỷ trọng đáng kể: doanh thu bán hàng cho bên liên quan đạt 63.4 tỷ VND (11.8% tổng doanh thu), mua hàng từ bên liên quan đạt 11.5 tỷ VND (2.3% giá vốn). Các khoản phải thu ngắn hạn từ bên liên quan lên đến 16.3 tỷ VND. Chủ tịch HĐQT Ông Ngô Hoàng Phương đã dùng tài sản cá nhân (quyền sử dụng đất, quyền sở hữu nhà) để bảo đảm cho khoản vay của Công ty tại Vietcombank. Thu nhập của các quản lý chủ chốt tăng mạnh trong năm (Ông Ngô Hoàng Phương: 666 triệu VND, tăng 3 lần so với năm trước). Mối quan hệ kinh doanh tập trung vào hệ sinh thái VNPT có thể tạo ra rủi ro phụ thuộc và giao dịch không hoàn toàn độc lập.', 'Tổng nợ vay ngắn hạn tại ngày 31/12/2025 là 42.4 tỷ VND, tăng 26.7% so với đầu năm (33.5 tỷ VND). Công ty có 4 hợp đồng tín dụng với hạn mức tổng cộng 265 tỷ VND từ VIB, Vietcombank, BIDV và TPBank. Tất cả các khoản vay đều có tài sản bảo đảm bao gồm hàng hóa, khoản phải thu, quyền sử dụng đất và tài sản gắn liền với đất của Chủ tịch HĐQT. Chi phí lãi vay năm 2025 là 2.6 tỷ VND. Đáng lưu ý, Công ty có lỗ chênh lệch tỷ giá lớn 2.1 tỷ VND trong năm do hoạt động giao dịch bằng ngoại tệ (USD, EUR). Tuy nhiên, Công ty có dòng tiền hoạt động kinh doanh dương 26.4 tỷ VND và tiền mặt 71.9 tỷ VND, đảm bảo khả năng thanh toán nợ ngắn hạn. Hàng tồn kho trị giá 85 tỷ VND đã được dùng để thế chấp cho các khoản vay.', 'Tổng giá trị hàng tồn kho là 100.4 tỷ VND, giảm nhẹ so với đầu năm (101.2 tỷ VND). Hàng hóa chiếm tỷ trọng lớn nhất (26.5 tỷ VND), tiếp theo là nguyên liệu vật liệu (33.5 tỷ VND) và chi phí SXKD dở dang (21.3 tỷ VND). Dự án điện mặt trời áp mái trị giá 2.1 tỷ VND đang trong giai đoạn triển khai, dự kiến hoàn thành quý I/2026. Hàng tồn kho dùng để thế chấp cho các khoản nợ là 85 tỷ VND. Không có dự phòng giảm giá hàng tồn kho được trích lập. Thành phẩm trị giá 19 tỷ VND và hàng hóa 26.5 tỷ VND cho thấy tốc độ luân chuyển tồn kho cần được theo dõi, đặc biệt khi giá vốn tăng 61.31% trong năm.', 6, 'Công ty Cổ phần Vinacap Kim Long đạt kết quả kinh doanh tăng trưởng mạnh trong năm 2025 với doanh thu thuần 535.8 tỷ VND (tăng 57.64%) và lợi nhuận sau thuế 2.3 tỷ VND (tăng 470% so với năm trước). Biên lợi nhuận gộp giảm từ 7.25% xuống 5.09% do giá vốn tăng nhanh hơn doanh thu, phản ánh áp lực cạnh tranh về giá. Lợi nhuận hoạt động kinh doanh đạt 2.9 tỷ VND, cải thiện đáng kể so với năm trước (0.9 tỷ VND). Dòng tiền hoạt động kinh doanh dương 26.4 tỷ VND cho thấy khả năng tạo tiền tốt. Công ty có vị thế thanh khoản hợp lý với tiền mặt 71.9 tỷ VND và đầu tư ngắn hạn 9 tỷ VND. Các rủi ro chính bao gồm: (1) phụ thuộc vào hệ sinh thái VNPT với giao dịch bên liên quan lớn; (2) lỗ chênh lệch tỷ giá 2.1 tỷ VND; (3) đòn bẩy nợ ngắn hạn tăng; (4) hàng tồn kho lớn và được dùng làm tài sản bảo đảm. Triển vọng: Công ty có kế hoạch mở rộng sản xuất với dự án điện mặt trời áp mái và đang mở rộng thị trường. Với tốc độ tăng trưởng doanh thu mạnh và cải thiện biên lợi nhuận hoạt động, Công ty có triển vọng tích cực nếu quản lý được rủi ro tỷ giá và duy trì quan hệ với hệ sinh thái VNPT.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VTE_2022_consolidated', 'VTE', 2022, 'consolidated', 'Các giao dịch với bên liên quan tập trung chủ yếu vào hệ sinh thái Tập đoàn Bưu chính Viễn thông Việt Nam (VNPT) - cổ đông lớn sở hữu 32% vốn. Doanh thu bán hàng cho bên liên quan đạt 61.957 tỷ đồng (chiếm ~14.7% tổng doanh thu), mua hàng từ bên liên quan đạt 11.101 tỷ đồng. Các giao dịch này là phù hợp với hoạt động sản xuất kinh doanh chính (sản xuất cáp viễn thông, thiết bị điện) của công ty, tuy nhiên sự phụ thuộc lớn vào hệ thống VNPT tạo ra rủi ro tập trung khách hàng. Không phát hiện dấu hiệu giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch giá bất thường.', 'Công ty có 82.741 tỷ đồng nợ vay ngắn hạn từ 7 ngân hàng thương mại, giảm so với mức 109.670 tỷ đồng đầu năm. Tài sản thế chấp chủ yếu là hàng hóa và khoản phải thu. Chi phí lãi vay năm 2022 là 5.973 tỷ đồng. Đặc biệt, Công ty ghi nhận lỗ chênh lệch tỷ giá 1.670 tỷ đồng do hoạt động vay ngoại tệ. Chi phí lãi vay không được trừ thuế theo Nghị định 132/2020/NĐ-CP lên tới 2.695 tỷ đồng, cho thấy mức đòn bẩy tài chính cao. Áp lực trả nợ ngắn hạn lớn với toàn bộ nợ vay đều có kỳ hạn dưới 1 năm.', 'Tổng hàng tồn kho cuối năm 134.119 tỷ đồng, giảm so với đầu năm 151.077 tỷ đồng. Chi phí sản xuất dở dang chiếm 24.674 tỷ đồng mà không có dự phòng giảm giá, tiềm ẩn rủi ro nếu sản phẩm không tiêu thụ được. Hàng tồn kho dùng để thế chấp cầm cố đạt 95.000 tỷ đồng. Thành phẩm và hàng hóa chiếm tỷ trọng lớn (70.040 tỷ đồng), phản ánh nhu cầu thị trường giảm (doanh thu giảm 25.5%). Tuy nhiên, Công ty không trích lập dự phòng giảm giá hàng tồn kho cho bất kỳ mục nào.', 6, 'Công ty Cổ phần Vinacap Kim Long là doanh nghiệp sản xuất cáp viễn thông, dây dẫn điện thuộc hệ sinh thái VNPT. Năm 2022, doanh thu giảm 25.5% (từ 564.426 tỷ xuống 420.736 tỷ đồng), lợi nhuận trước thuế giảm 42.5% (từ 4.400 tỷ xuống 2.530 tỷ đồng) do ảnh hưởng kinh tế hậu Covid-19. Biên lợi nhuận gộp cải thiện nhẹ (~9.8%). Nợ vay ngắn hạn chiếm tỷ trọng cao (27.8% tổng tài sản), tất cả đều có kỳ hạn dưới 1 năm tạo áp lực tái cấp vốn liên tục. Lỗ tỷ giá 1.670 tỷ đồng phản ánh rủi ro ngoại hối đáng kể. Công ty có 1.595 tỷ đồng nợ xấu phải thu từ 6 khách hàng khó đòi. Điểm tích cực là nợ vay đã giảm mạnh trong năm, dòng tiền hoạt động kinh doanh dương 36.748 tỷ đồng (so với âm 42.499 tỷ năm trước), cho thấy cải thiện khả năng tạo tiền. Tuy nhiên, triển vọng tăng trưởng phụ thuộc lớn vào hệ sinh thái VNPT và ngành viễn thông.'),
('VTO_2016_consolidated', 'VTO', 2016, 'consolidated', 'Công ty có nhiều giao dịch với công ty mẹ và các công ty liên quan, bao gồm doanh thu bán hàng, cung cấp dịch vụ và mua hàng hóa. Giá trị giao dịch lớn, tạo rủi ro phụ thuộc và tính độc lập trong kinh doanh.', 'Nợ vay ngân hàng được đảm bảo bằng tài sản cố định hữu hình, lãi suất từ 2.49% đến 8%. Nợ dài hạn chiếm tỷ trọng cao, áp lực trả nợ trung bình do dòng tiền kinh doanh dương.', 'Hàng tồn kho tăng từ 53 tỷ lên 68 tỷ VND, chủ yếu là nguyên vật liệu và hàng gửi đi bán. Có nguy cơ tồn kho dở dang hoặc giảm giá nếu thị trường biến động.', 6, 'Doanh thu giảm nhưng lợi nhuận tăng do giảm giá vốn và chi phí tài chính. Tình hình tài chính cải thiện, với tỷ suất lợi nhuận gộp khoảng 19.7%. Tuy nhiên, công ty có nhiều giao dịch bên liên quan và nợ vay lớn, cần quản trị rủi ro hiệu quả.'),
('VTE_2020_consolidated', 'VTE', 2020, 'consolidated', 'Doanh thu bán hàng cho Tập đoàn Bưu chính Viễn thông Việt Nam (cổ đông lớn) chiếm tỷ trọng rất lớn trong tổng doanh thu (hơn 40%). Mua hàng từ Tập đoàn này cũng chiếm tỷ trọng đáng kể. Cần đánh giá tính công bằng và điều khoản của các giao dịch này, nhưng chưa phát hiện dấu hiệu bất thường rõ ràng.', 'Nợ vay ngắn hạn chiếm tỷ trọng lớn trong tổng nợ phải trả (hơn 46% tổng nguồn vốn). Áp lực trả nợ trong ngắn hạn là đáng kể. Tài sản đảm bảo chủ yếu là hàng hóa và khoản phải thu, phụ thuộc vào hoạt động kinh doanh. Công ty có nguồn tiền gửi ngân hàng và khoản phải thu để bù đắp.', 'Hàng tồn kho lớn, đặc biệt là chi phí sản xuất kinh doanh dở dang (31.308.587.056 VND) và thành phẩm (40.465.878.087 VND). Hàng tồn kho tăng giảm không đồng đều với doanh thu, có nguy cơ chậm luân chuyển hoặc ứ đọng do ảnh hưởng của dịch bệnh.', 6, 'Công ty hoạt động trong lĩnh vực sản xuất và thương mại thiết bị viễn thông, chịu ảnh hưởng tiêu cực từ đại dịch Covid-19 trong năm 2020, thể hiện qua sự sụt giảm doanh thu. Tuy nhiên, công ty đã cải thiện biên lợi nhuận gộp và kiểm soát chi phí, giúp lợi nhuận sau thuế tăng 27,6%. Nợ vay ngắn hạn lớn tạo áp lực tài chính, nhưng công ty có khả năng thanh toán từ dòng tiền kinh doanh. Hàng tồn kho lớn cần được quản lý chặt chẽ. Các giao dịch với bên liên quan là đáng kể nhưng không có dấu hiệu bất thường rõ ràng. Điểm rủi ro quản trị ở mức trung bình do cơ cấu sở hữu và giao dịch với cổ đông lớn.'),
('VTE_2021_consolidated', 'VTE', 2021, 'consolidated', 'Doanh thu bán hàng và mua hàng với bên liên quan (Tập đoàn Bưu chính Viễn thông Việt Nam và các công ty con) chiếm tỷ trọng lớn trong hoạt động kinh doanh. Không có dấu hiệu giao dịch bất thường rõ ràng nhưng cần giám sát mối quan hệ phụ thuộc.', 'Nợ vay ngắn hạn lớn (hơn 109 tỷ VNĐ), được đảm bảo chủ yếu bằng hàng hóa và khoản phải thu. Công ty có thể chịu áp lực thanh toán nợ ngắn hạn và phụ thuộc vào việc quản lý tài sản lưu động.', 'Giá trị hàng tồn kho cao (hơn 151 tỷ VNĐ), bao gồm hàng hóa, thành phẩm và chi phí sản xuất dở dang. Không có dự phòng giảm giá, cần theo dõi khả năng tiêu thụ và nguy cơ ứ đọng.', 5, 'Doanh thu và lợi nhuận sau thuế năm 2021 giảm so với năm 2020 do ảnh hưởng của đại dịch Covid-19. Công ty có cơ cấu tài chính với nợ vay ngắn hạn lớn và hàng tồn kho cao, cần quản lý thanh khoản và rủi ro tồn kho. Giao dịch với bên liên quan chiếm tỷ trọng đáng kể. Điểm rủi ro quản trị ở mức trung bình.'),
('VTE_2018_consolidated', 'VTE', 2018, 'consolidated', 'Công ty có giao dịch mua bán lớn với Tập đoàn Bưu chính Viễn thông Việt Nam (cổ đông lớn 32% vốn). Doanh thu bán hàng cho bên liên quan chiếm tỷ trọng đáng kể trong tổng doanh thu (228,2 tỷ/710,4 tỷ = 32,1%). Tuy nhiên, báo cáo không công khai chi tiết về giá chuyển nhượng, lãi suất giao dịch hay điều khoản thanh toán đặc biệt nên khó đánh giá đầy đủ mức độ bất thường. Số dư phải thu từ bên liên quan giảm mạnh từ 74,9 tỷ xuống 36,0 tỷ cho thấy khả năng thu hồi cải thiện.', 'Công ty vay ngắn hạn từ 4 ngân hàng với tổng dư nợ 116,6 tỷ VNĐ, toàn bộ là nợ ngắn hạn không có nợ dài hạn. Lãi suất dao động 5,5%-7,5%/năm. Áp lực nợ ngắn hạn ở mức cao với tỷ lệ nợ vay/tổng tài sản = 30,9%. Dòng tiền hoạt động kinh doanh năm 2018 bị âm (-4,2 tỷ) đặt ra lo ngại về khả năng trả nợ. Một khoản vay HSBC (52,2 tỷ) và OceanBank (9,9 tỷ) không có tài sản đảm bảo.', 'Hàng tồn kho tăng mạnh 16,3% từ 156,0 tỷ lên 181,5 tỷ VNĐ, chiếm tỷ trọng lớn 48,1% tổng tài sản. Thành phẩm tăng hơn gấp đôi từ 29,0 tỷ lên 68,9 tỷ cho thấy có khả năng ứ đọng hàng tồn kho. Chi phí sản xuất dở dang ở mức cao 38,1 tỷ. Có 35,7 tỷ hàng tồn kho dùng làm tài sản thế chấp cho vay. Công ty không trích lập dự phòng giảm giá hàng tồn kho.', 5, 'Công ty Cổ phần Viễn thông Điện tử Vinacap có doanh thu năm 2018 đạt 710,4 tỷ VNĐ tăng 18,3% so với năm trước, nhưng lợi nhuận sau thuế giảm 49,1% xuống 2,5 tỷ VNĐ. Biên lợi nhuận gộp chỉ đạt 6,0%. Công ty đối mặt với nhiều rủi ro: (1) Dòng tiền hoạt động kinh doanh âm -4,2 tỷ; (2) Nợ ngắn hạn cao 205,9 tỷ VNĐ; (3) Hàng tồn kho tăng mạnh và chiếm tỷ trọng lớn; (4) Phụ thuộc lớn vào giao dịch với cổ đông lớn Tập đoàn Bưu chính Viễn thông Việt Nam. Ban lãnh đạo có biến động nhiều trong năm 2018 với nhiều vị trí miễn nhiệm/bổ nhiệm. Công ty đã chi trả cổ tức 2% vốn điều lệ (3,12 tỷ VNĐ) dù lợi nhuận giảm.'),
('VTE_2017_consolidated', 'VTE', 2017, 'consolidated', 'Công ty có giao dịch lớn với cổ đông lớn là Tập đoàn Bưu chính Viễn thông Việt Nam (VNPT). Doanh thu bán hàng cho VNPT đạt 288 tỷ VND (chiếm 48% tổng doanh thu), mua hàng từ VNPT đạt 140 tỷ VND. Số dư phải thu từ VNPT cuối năm là 74.8 tỷ VND, chiếm 55% tổng phải thu khách hàng. Mối quan hệ kinh doanh phụ thuộc lớn vào cổ đông lớn có thể tạo rủi ro về giá chuyển nhượng và điều kiện thanh toán.', 'Toàn bộ nợ vay là ngắn hạn với tổng số dư 124.8 tỷ VND, chiếm 33% tổng tài sản. Công ty vay từ 5 ngân hàng với lãi suất VND 4-7%/năm, USD 4%/năm. Áp lực trả nợ ngắn hạn lớn, phải thường xuyên đảo nợ. Một số khoản vay không có tài sản đảm bảo (HSBC, Bản Việt), một số được đảm bảo bằng quyền đòi nợ từ phải thu khách hàng.', 'Hàng tồn kho tăng mạnh từ 122.2 tỷ lên 156 tỷ VND (tăng 27.6%), trong đó hàng hóa tăng từ 11 tỷ lên 44.6 tỷ VND. Chi phí sản xuất dở dang 37.6 tỷ VND, có nguy cơ bị ứ đọng nếu đơn hàng chậm. Không trích lập dự phòng giảm giá hàng tồn kho.', 6, 'Công ty có quy mô vốn chủ sở hữu 171.8 tỷ VND, doanh thu 600.7 tỷ VND. Lợi nhuận sau thuế giảm 60% từ 12.3 tỷ xuống 4.9 tỷ VND. Biên lợi nhuận gộp chỉ 6.85%. Nợ ngắn hạn chiếm tỷ trọng cao với 124.8 tỷ VND. Công ty có dòng tiền hoạt động kinh doanh dương 8.4 tỷ VND. Phụ thuộc lớn vào Tập đoàn VNPT trong cả đầu ra và đầu vào. Ban lãnh đạo có nhiều thay đổi trong năm 2017.'),
('VTE_2016_consolidated', 'VTE', 2016, 'consolidated', 'Doanh nghiệp có giao dịch mua bán hàng hóa đáng kể với cổ đông lớn Tập đoàn Bưu chính Viễn thông Việt Nam, với doanh thu bán hàng 343 tỷ VNĐ và mua vật tư 70 tỷ VNĐ, cùng số dư phải thu 88 tỷ VNĐ, tiềm ẩn rủi ro về giao dịch không công bằng hoặc phụ thuộc vào bên liên quan.', 'Nợ vay ngắn hạn là 122.2 tỷ VNĐ, với chi phí lãi vay 11.3 tỷ VNĐ trong năm, cho thấy áp lực trả nợ cao. Tài sản cố định thế chấp có giá trị 7.8 tỷ VNĐ.', 'Tồn kho dở dang lớn lên đến 42.9 tỷ VNĐ, chiếm tỷ trọng cao, cần theo dõi khả năng hoàn thành và tiêu thụ để tránh ứ đọng.', 5, 'Công ty có lợi nhuận sau thuế tăng từ 10.5 tỷ lên 12.3 tỷ VNĐ, nhưng cơ cấu tài chính dựa nhiều vào nợ vay ngắn hạn. Giao dịch với bên liên quan lớn có thể ảnh hưởng đến tính minh bạch. Triển vọng phụ thuộc vào quản lý nợ và kiểm soát tồn kho.'),
('VTE_2015_consolidated', 'VTE', 2015, 'consolidated', 'Công ty có giao dịch mua bán lớn với cổ đông lớn là Tập đoàn Bưu chính Viễn thông Việt Nam (VNPT). Doanh thu bán hàng cho bên liên quan chiếm tỷ trọng cao (khoảng 51% tổng doanh thu), cho thấy sự phụ thuộc lớn vào cổ đông lớn, tạo rủi ro tập trung khách hàng.', 'Công ty có nợ vay ngắn hạn lớn (133 tỷ VNĐ), tương đương gần bằng vốn chủ sở hữu (155 tỷ VNĐ). Các khoản vay chủ yếu được đảm bảo bằng quyền đòi nợ và hàng tồn kho. Áp lực trả nợ trong ngắn hạn là đáng kể, tiềm ẩn rủi ro thanh khoản.', 'Hàng tồn kho tăng mạnh (từ 129 tỷ lên 165 tỷ VNĐ), trong đó có khoản mục ''Chi phí sản xuất kinh doanh dở dang'' lớn (39 tỷ VNĐ). Điều này phản ánh công ty đang tập trung sản xuất cáp quang, nhưng cũng tiềm ẩn rủi ro ứ đọng vốn nếu sản phẩm tồn kho không được tiêu thụ nhanh.', 7, 'Công ty có sự tăng trưởng về doanh thu bán thành phẩm và lợi nhuận sau thuế (từ 5.9 tỷ lên 10.5 tỷ VNĐ). Tuy nhiên, cấu trúc tài chính rủi ro cao với tỷ lệ nợ vay ngắn hạn/vốn chủ sở hữu gần 1:1, tập trung doanh thu vào một bên liên quan lớn, và hàng tồn kho tăng nhanh. Công ty cần cải thiện quản lý vốn lưu động và đa dạng hóa khách hàng để giảm thiểu rủi ro.'),
('VTD_2025_consolidated', 'VTD', 2025, 'consolidated', 'Doanh nghiệp có giao dịch đáng kể với các bên liên quan. Tổng đầu tư vào công ty liên kết trong năm đạt 78 tỷ VND với 4 công ty liên kết trong các lĩnh vực đa dạng (y tế, nhà hàng, bất động sản nghỉ dưỡng, trồng rừng). Chủ tịch HĐQT nhận tạm ứng 7.18 tỷ VND. Công ty cho cá nhân vay 6 tỷ VND với lãi suất 4.5%/năm. Có hiện tượng thay đổi mục đích sử dụng vốn huy động từ việc mua xe sang đầu tư vào các công ty liên kết. Công ty Cổ phần Xã hội Hoàng Kim Tây Nguyên (liên kết) chưa hoạt động SXKD, đang thực hiện dự án trồng rừng chưa thu hoạch.', 'Tổng nợ vay cuối năm đạt khoảng 78.4 tỷ VND (ngắn hạn 61.3 tỷ + dài hạn 17.1 tỷ), tăng mạnh so với năm trước. Nợ ngắn hạn tăng từ 48.7 tỷ lên 61.3 tỷ VND. Chi phí lãi vay năm nay là 5.9 tỷ VND, chiếm tỷ trọng lớn trong cơ cấu chi phí. Lãi suất biến động theo từng thời điểm. Tài sản cố định trị giá sổ sách 52.2 tỷ VND đã được thế chấp đảm bảo cho các khoản vay. Công ty còn nợ dài hạn đến hạn trả 7.5 tỷ VND sắp chuyển sang ngắn hạn trong năm tới.', 'Hàng tồn kho giảm nhẹ từ 6.3 tỷ xuống 5.6 tỷ VND, chủ yếu là chi phí sản xuất kinh doanh dở dang. Không có dự phòng giảm giá hàng tồn kho. Rủi ro tồn kho thấp do giá trị nhỏ và không có dấu hiệu ứ đọng.', 7, 'Tập đoàn Vietourist Holdings đã có sự phục hồi mạnh về kết quả kinh doanh năm 2025, chuyển từ lỗ 5.4 tỷ năm trước sang lãi 2.4 tỷ VND. Doanh thu tăng 10.8%, biên lợi nhuận gộp cải thiện từ 10.2% lên 12.6%. Công ty đã tăng vốn điều lệ gấp đôi từ 120 tỷ lên 240 tỷ VND thông qua phát hành cổ phiếu. Tuy nhiên, dòng tiền hoạt động kinh doanh âm nặng (-45.6 tỷ), chủ yếu do tăng mạnh các khoản phải thu. Công ty đang mở rộng đầu tư vào nhiều công ty liên kết đa ngành (y tế, nhà hàng, nghỉ dưỡng, trồng rừng) với tổng vốn góp 78 tỷ VND trong năm. Nợ vay tăng mạnh với chi phí lãi vay 5.9 tỷ VND/năm. Ban lãnh đạo thay đổi nhiều trong năm 2025. Cần theo dõi khả năng thu hồi các khoản đầu tư và dòng tiền kinh doanh.'),
('VTD_2024_parent', 'VTD', 2024, 'parent', 'Công ty có giao dịch với các bên liên quan bao gồm công ty con (Công ty TNHH Vận tải Vietrip) và các công ty liên kết (đã thoái vốn). Các giao dịch chủ yếu là mua/bán dịch vụ và cho vay. Giao dịch cho vay có tính lãi, không có dấu hiệu bất thường rõ ràng. Tuy nhiên, cần theo dõi mối quan hệ và giao dịch với công ty con.', 'Nợ vay ngắn hạn tăng mạnh từ 25,8 tỷ lên 47,8 tỷ VND, trong khi nợ dài hạn giảm từ 22,9 tỷ xuống 7,0 tỷ VND. Tổng nợ vay (ngắn+dài hạn) tăng từ 48,8 tỷ lên 54,8 tỷ VND. Công ty có khả năng thanh toán các khoản vay (tiền và đầu tư ngắn hạn đạt 15,8 tỷ). Tài sản thế chấp chủ yếu là phương tiện vận tải và tiền gửi có kỳ hạn.', 'Hàng tồn kho tăng nhẹ từ 7,1 tỷ lên 7,6 tỷ VND, chủ yếu là chi phí sản xuất kinh doanh dở dang (có thể liên quan đến tour du lịch đang thực hiện). Không có dự án bất động sản dở dang. Rủi ro tồn kho thấp.', 3, 'Công ty hoạt động trong lĩnh vực du lịch, lữ hành. Doanh thu tăng 8,5% nhưng lợi nhuận giảm mạnh do chi phí tài chính và chi phí khác tăng cao (phạt vi phạm hợp đồng 1,8 tỷ). Nợ vay tăng, áp lực tài chính tăng. Công ty đã thoái vốn khỏi hai công ty liên kết trong năm. Ban lãnh đạo có biến động (miễn nhiệm, bầu mới). Điểm rủi ro quản trị ở mức trung bình.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VTD_2025_parent', 'VTD', 2025, 'parent', 'Doanh nghiệp có nhiều giao dịch với các bên liên quan, bao gồm góp vốn bằng tiền lớn vào công ty liên kết và mua/bán dịch vụ với công ty con. Không có dấu hiệu bất thường rõ ràng như cho vay không lãi suất, nhưng giá trị giao dịch đáng kể đòi hỏi sự giám sát.', 'Áp lực nợ vay trung bình với tổng nợ ngắn hạn khoảng 60 tỷ VND và nợ dài hạn khoảng 14 tỷ VND. Công ty thế chấp tài sản cố định và phương tiện vận tải, nhưng cho biết có khả năng thanh toán. Cần theo dõi dòng tiền và lãi suất biến động.', 'Rủi ro tồn kho thấp do giá trị tồn kho giảm so với đầu năm và không có dự phòng giảm giá. Hàng hóa và chi phí dở dang không bị ứ đọng.', 5, 'Công ty kinh doanh du lịch, doanh thu tăng trưởng lợi nhuận gộp cải thiện nhưng lợi nhuận sau thuế thấp. Tăng vốn chủ sở hữu thông qua phát hành cổ phiếu để tài trợ đầu tư và giảm đòn bẩy. Triển vọng trung bình phụ thuộc vào ngành du lịch và quản lý hiệu quả các khoản đầu tư liên kết.'),
('VTD_2023_parent', 'VTD', 2023, 'parent', 'Doanh nghiệp có giao dịch cho vay không lãi suất với công ty con Công ty TNHH Vận tải Vietrip, điều này có thể ảnh hưởng đến lợi ích của cổ đông thiểu số nếu có. Tuy nhiên, không có dấu hiệu giao dịch bất thường khác.', 'Áp lực nợ vay khá lớn với tổng nợ phải trả khoảng 75 tỷ VNĐ, trong đó nợ ngắn hạn 52 tỷ và nợ dài hạn 23 tỷ. Tuy nhiên, công ty có tài sản thế chấp và khả năng trả nợ được đánh giá là có thể.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang và hàng hóa, không có dấu hiệu tồn kho ứ đọng hay dự phòng giảm giá.', 3, 'Công ty hoạt động trong ngành du lịch, doanh thu tăng trưởng nhưng lợi nhuận giảm do chi phí tăng. Cơ cấu tài sản và vốn có sự cân đối. Tuy nhiên, cần lưu ý đến các giao dịch với bên liên quan và áp lực nợ vay.'),
('VTD_2023_consolidated', 'VTD', 2023, 'consolidated', 'Các giao dịch với bên liên quan bao gồm mua dịch vụ và góp vốn, với tổng giá trị không lớn so với quy mô tài sản, không có dấu hiệu bất thường như cho vay không lãi suất.', 'Nợ vay tổng cộng khoảng 45.7 tỷ VND, được đảm bảo bằng tài sản cố định và quyền sử dụng đất. Tuy nhiên, dòng tiền hoạt động kinh doanh âm, tạo áp lực trả nợ, nhưng công ty có khả năng trả nợ từ hoạt động đầu tư và tài chính.', 'Hàng tồn kho chủ yếu là chi phí sản xuất dở dang và hàng hóa, giá trị nhỏ và không có dự phòng, rủi ro thấp.', 4, 'Lợi nhuận giảm mạnh so với năm trước do chi phí bán hàng và quản lý tăng cao. Nợ vay ở mức trung bình, có tài sản thế chấp. Công ty hoạt động trong ngành du lịch có tính chu kỳ, cần theo dõi dòng tiền và khả năng sinh lời.'),
('VTD_2022_parent', 'VTD', 2022, 'parent', 'Công ty có giao dịch với các công ty con và công ty liên kết, bao gồm mua hàng hóa, dịch vụ và vay mượn. Các giao dịch này có vẻ bình thường, nhưng cần theo dõi do số lượng lớn.', 'Công ty có nợ vay ngắn hạn và dài hạn, được đảm bảo bằng tài sản cố định. Áp lực nợ vay ở mức trung bình với tỷ lệ nợ/tài sản khoảng 35%.', 'Hàng tồn kho chủ yếu là chi phí sản xuất dở dang và hàng hóa, không có dự phòng giảm giá, rủi ro thấp.', 3, 'Công ty có tình hình tài chính ổn định với biên lợi nhuận gộp khoảng 20%. Tuy nhiên, cần lưu ý đến dòng tiền từ hoạt động kinh doanh âm và các giao dịch với bên liên quan.'),
('VTD_2022_consolidated', 'VTD', 2022, 'consolidated', 'Tập đoàn có quan hệ giao dịch đáng chú ý với Công ty Cổ phần Tập đoàn Hoàng Kim Tây Nguyên (công ty liên kết, tỷ lệ sở hữu 21.52%). Các giao dịch bao gồm: mua hàng hóa 248 triệu, góp vốn bằng tiền 34.5 tỷ, cho vay và trả nợ trước cho người bán 2.5 tỷ, phải thu 1.8 tỷ. Năm trước có phát sinh lãi vay 516 triệu từ công ty liên kết. Mối quan hệ phức tạp khi cùng lúc vừa mua hàng, vừa góp vốn lớn, vừa cho vay. Công ty con Kỹ thuật Công nghệ Vietech cũng có quan hệ phức tạp khi Công ty mẹ sở hữu 99.44%. Tuy nhiên, tổng thể giao dịch với bên liên quan chưa ở mức quá bất thường.', 'Tổng nợ vay khoảng 45 tỷ VNĐ, trong đó nợ ngắn hạn 21.9 tỷ và nợ dài hạn 23.2 tỷ. Chi phí lãi vay tăng mạnh từ 1.9 tỷ lên 3.0 tỷ. Phần lớn tài sản cố định hữu hình (38.7 tỷ) và quyền sử dụng đất (19 tỷ) đã được thế chấp đảm bảo cho các khoản vay ngân hàng. Lưu chuyển tiền thuần từ hoạt động kinh doanh âm 40.7 tỷ, cho thấy áp lực thanh toán đáng kể. Công ty chủ yếu phụ thuộc vào dòng tiền từ hoạt động tài chính (phát hành cổ phiếu 60 tỷ, đi vay mới 83.2 tỷ) để bù đắp.', 'Hàng tồn kho ở mức thấp 5.6 tỷ (giảm từ 8.3 tỷ đầu năm), chủ yếu là chi phí sản xuất kinh doanh dở dang 5.5 tỷ và hàng hóa 61 triệu. Không có dự phòng giảm giá hàng tồn kho. Rủi ro tồn kho thấp do quy mô nhỏ so với tổng tài sản 225.7 tỷ.', 5, 'Vietourist Holdings (VTD) hoạt động trong ngành du lịch với doanh thu 173.5 tỷ, tăng 15.7% so với năm trước. Biên lợi nhuận gộp cải thiện mạnh lên 18.2% (so với 2.7% năm trước) do cơ cấu doanh thu dịch vụ tăng mạnh. Lợi nhuận sau thuế đạt 10.7 tỷ, tương đương năm trước. Công ty tăng vốn điều lệ gấp đôi lên 120 tỷ trong năm 2022, mở rộng đầu tư vào công ty vận tải Vietrip (100%) và công ty liên kết Hoàng Kim Tây Nguyên (21.52%). Đáng lưu ý: dòng tiền hoạt động kinh doanh âm nặng (-40.7 tỷ) bù đắp bởi phát hành cổ phiếu và đi vay mới. Tổng tài sản tăng gấp đôi lên 225.7 tỷ, trong đó phải thu và trả trước tăng mạnh (95.7 tỷ) phản ánh mở rộng hoạt động kinh doanh. Rủi ro chính nằm ở áp lực nợ vay và khả năng tạo dòng tiền từ hoạt động kinh doanh.'),
('VTD_2021_parent', 'VTD', 2021, 'parent', 'Công ty có giao dịch đáng kể với Công ty CP Tập đoàn Hoàng Kim Tây Nguyên (liên quan đến Chủ tịch HĐQT Trần Văn Tuân) bao gồm cho vay ngắn hạn lãi suất 12%/năm, mua dịch vụ và có số dư trả trước người bán lớn 1,18 tỷ đồng. Công ty con Vietech cũng phát sinh giao dịch mua hàng 3,96 tỷ đồng và số dư phải trả 570 triệu đồng. Các giao dịch với bên liên quan chiếm tỷ trọng tương đối lớn trong tổng tài sản và doanh thu, tuy nhiên mức lãi suất cho vay 12%/năm là hợp lý thị trường.', 'Tổng nợ vay tăng mạnh từ 9,1 tỷ lên 24,5 tỷ đồng (+168%), trong đó nợ dài hạn mới phát sinh 13 tỷ đồng để mua bất động sản. Nợ ngắn hạn tăng do hạn mức tín dụng mới tại MB Bank. Tài sản thế chấp chủ yếu là quyền sử dụng đất 154 Lý Chính Thắng (nguyên giá 19 tỷ) và TSCĐ. Áp lực trả nợ trong năm tới khoảng 11,5 tỷ nợ ngắn hạn, tuy nhiên dòng tiền từ hoạt động kinh doanh dương và có khoản đầu tư ngắn hạn 20 tỷ có thể thanh khoản.', 'Hàng tồn kho tăng gấp 2,7 lần từ 2,3 tỷ lên 6,3 tỷ đồng, phản ánh chiến lược mở rộng kinh doanh thương mại khi ngành du lịch bị ảnh hưởng bởi Covid-19. Không có dự phòng giảm giá hàng tồn kho được trích lập. Rủi ro hàng tồn kho tăng cao trong bối cảnh kinh doanh thương mại mới, cần theo dõi khả năng tiêu thụ.', 5, 'Công ty đã chuyển hướng mạnh sang kinh doanh thương mại khi ngành du lịch bị ảnh hưởng bởi Covid-19, đạt doanh thu 130,7 tỷ đồng (+25%) và lợi nhuận sau thuế 10,9 tỷ đồng (+233%). Biên lợi nhuận gộp giảm mạnh từ 8,1% xuống 3,1% do tỷ trọng thương mại tăng. Điểm tích cực là doanh thu hoạt động tài chính 15 tỷ (chủ yếu lãi chuyển nhượng cổ phần 14,4 tỷ). Tổng tài sản tăng 30% lên 115 tỷ, nợ phải trả tăng 70% do mở rộng vay vốn đầu tư bất động sản. Công ty có công ty con Vietech và nhiều chi nhánh/VPĐD trên toàn quốc. Rủi ro chính là giao dịch bên liên quan, đòn bẩy tài chính tăng cao và phụ thuộc vào hoạt động thương mại mới.'),
('VTD_2021_consolidated', 'VTD', 2021, 'consolidated', 'Giao dịch với bên liên quan Công ty CP Tập đoàn Hoàng Kim Tây Nguyên bao gồm cho vay ngắn hạn, mua dịch vụ và trả nợ. Các giao dịch có vẻ bình thường nhưng cần giám sát do mối quan hệ cá nhân.', 'Nợ vay tăng mạnh với nợ ngắn hạn 24,5 tỷ VNĐ và nợ dài hạn 13 tỷ VNĐ, chủ yếu từ ngân hàng. Tài sản thế chấp bao gồm tiền, bất động sản và phương tiện vận tải. Áp lực trả nợ ngắn hạn cao, nhưng công ty có tài sản đảm bảo.', 'Hàng tồn kho chủ yếu là hàng hóa và chi phí sản xuất kinh doanh dở dang, không có dự phòng giảm giá. Rủi ro tồn kho thấp do không có hàng hóa lỗi thời hoặc hư hỏng được ghi nhận.', 5, 'Công ty có kết quả kinh doanh cải thiện với lợi nhuận tăng gấp 3 lần so với năm trước, nhưng nợ vay tăng cao gây áp lực thanh khoản. Doanh thu chủ yếu từ hoạt động thương mại và dịch vụ, với biên lợi nhuận gộp thấp. Triển vọng phụ thuộc vào việc quản lý nợ và khai thác hiệu quả tài sản.'),
('VTC_2025_parent', 'VTC', 2025, 'parent', 'Doanh nghiệp có nhiều giao dịch với các bên liên quan thuộc Tập đoàn Bưu chính Viễn thông Việt Nam, chiếm tỷ trọng lớn trong doanh thu và chi phí. Tuy nhiên, không có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn với công ty sân sau.', 'Nợ vay ngắn hạn tăng mạnh từ 84,7 tỷ lên 216,5 tỷ VNĐ, gây áp lực trả nợ lớn. Công ty sử dụng nhiều tài sản thế chấp (tiền gửi, phải thu, hàng tồn kho, máy móc) để đảm bảo khoản vay. Áp lực lãi vay cao với chi phí lãi vay hơn 11 tỷ VNĐ.', 'Hàng tồn kho tăng từ 76,9 tỷ lên 150,5 tỷ VNĐ, chủ yếu là chi phí sản xuất kinh doanh dở dang và hàng hóa. Công ty không ghi nhận dự phòng giảm giá, cần theo dõi khả năng lưu thông và nguy cơ tồn kho chậm luân chuyển.', 6, 'Doanh nghiệp có sự tăng trưởng mạnh về doanh thu (hơn gấp đôi) và lợi nhuận tăng, nhưng nợ vay và hàng tồn kho tăng nhanh gây áp lực tài chính và rủi ro hoạt động. Khả năng thanh khoản bị ảnh hưởng bởi dòng tiền hoạt động kinh doanh âm. Cần theo dõi chặt chẽ quản lý vốn lưu động và rủi ro nợ.'),
('VTC_2024_parent', 'VTC', 2024, 'parent', 'Công ty có giao dịch lớn với các bên liên quan thuộc Tập đoàn Bưu chính Viễn thông Việt Nam (VNPT). Doanh thu từ các đơn vị thành viên VNPT chiếm tỷ trọng lớn trong tổng doanh thu. Công ty cũng có giao dịch cho vay với công ty con (STID) với lãi suất 10%/năm - mức lãi suất thị trường, không có dấu hiệu bất thường rõ ràng. Tuy nhiên, các khoản phải thu từ các đơn vị VNPT có số dư lớn, đặc biệt Công ty Công nghệ thông tin VNPT (21,2 tỷ), Tổng Công ty Hạ tầng mạng VNPT-Net (4,7 tỷ). Giao dịch mua hàng với công ty con STID có giá trị lớn (16,7 tỷ) theo hợp đồng 15,8 tỷ. Cần theo dõi tính độc lập và giá cả giao dịch giữa các bên.', 'Tổng nợ vay và nợ thuê tài chính là 86,08 tỷ VNĐ, trong đó vay ngắn hạn chiếm 84,73 tỷ (98,4%). Chi phí lãi vay năm 2024 là 11,49 tỷ VNĐ, chiếm tỷ trọng đáng kể so với lợi nhuận trước thuế (6,05 tỷ). Áp lực nợ vay ngắn hạn cao với chu kỳ đáo hạn ngắn (dưới 9 tháng với hầu hết khoản vay). Tài sản thế chấp bao gồm tiền gửi ngân hàng, phải thu khách hàng, TSCĐ hữu hình và bất động sản. Công ty vay cá nhân tới 36 tỷ với lãi suất 10-12%/năm cho thấy phụ thuộc vào nguồn vốn cá nhân. Tỷ lệ nợ/vốn chủ sở hữu là 2,61 lần, cho thấy đòn bẩy tài chính cao.', 'Hàng tồn kho tổng cộng 76,95 tỷ VNĐ, tăng từ 68,83 tỷ đầu năm. Trong đó chi phí SXKD dở dang chiếm 86,7% (66,69 tỷ) - đây là khoản mục lớn nhất và cần được theo dõi sát sao về tiến độ hoàn thành. Công ty không có hàng tồn kho ứ động, kém phẩm chất tại ngày 31/12/2024. Dự phòng hàng tồn kho không được trích lập. Hàng hóa kinh doanh thương mại chiếm 8,83 tỷ, phù hợp với hoạt động thương mại thiết bị viễn thông.', 5, 'Công ty Cổ phần Viễn thông VTC hoạt động trong lĩnh vực viễn thông và thương mại thiết bị. Năm 2024 ghi nhận kết quả kinh doanh tích cực với doanh thu thuần tăng 42% đạt 215,47 tỷ, lợi nhuận sau thuế đạt 3,43 tỷ (tăng 214% so với năm trước). Tuy nhiên, công ty đối mặt với rủi ro đáng kể từ tỷ lệ đòn bẩy cao (nợ/vốn = 2,61 lần), chi phí lãi vay lớn (11,49 tỷ) gần gấp đôi lợi nhuận trước thuế. Hàng tồn kho dở dang lớn (66,7 tỷ) cần được kiểm soát. Giao dịch với các bên liên quan (VNPT Group) chiếm tỷ trọng lớn, tạo rủi ro tập trung khách hàng. Công ty có khoản đầu tư vào công ty con 19,2 tỷ đã trích lập dự phòng 899 triệu. Điểm rủi ro quản trị ở mức trung bình (5/10) do giao dịch bên liên quan phức tạp nhưng đã có công bố minh bạch. Triển vọng trung hạn phụ thuộc vào khả năng kiểm soát chi phí lãi vay và quản lý dòng tiền.'),
('VTC_2024_consolidated', 'VTC', 2024, 'consolidated', 'Doanh nghiệp có giao dịch lớn với các bên thuộc Tập đoàn VNPT (cổ đông Nhà nước chiếm 46.67%). Tổng doanh thu từ nhóm VNPT chiếm tỷ trọng rất lớn (~152.7 tỷ VND/236.6 tỷ VND doanh thu thuần, tương đương ~65%). Điều này tạo ra rủi ro tập trung khách hàng cao. Công ty cũng cho vay/tạm ứng cho các thành viên ban lãnh đạo với tổng số dư cuối kỳ khoảng 2.8 tỷ VND (Lê Xuân Tiến 1.03 tỷ, Bùi Văn Bằng 572 triệu, Nguyễn Đức Long 406 triệu, v.v.), cho thấy kiểm soát nội bộ về giao dịch với bên liên quan có thể chưa chặt chẽ. Mặt khác, Công ty cũng vay cá nhân 36 tỷ VND với lãi suất 10-12%/năm để bổ sung vốn lưu động.', 'Nợ vay ngắn hạn ở mức cao (~80 tỷ VND), trong đó vay cá nhân chiếm 36 tỷ VND là đáng lo ngại do tính ổn định thấp. Tổng nợ phải trả (177.5 tỷ VND) lớn hơn nhiều so với vốn chủ sở hữu (80.5 tỷ VND), tỷ lệ nợ/vốn chủ sở hữu ~2.2 lần. Chi phí lãi vay năm 2024 là 11.27 tỷ VND, chiếm tỷ trọng đáng kể trong lợi nhuận gộp (48.5 tỷ). Công ty đã giảm được nợ từ 110.5 tỷ xuống 81 tỷ so với đầu năm, cho thấy nỗ lực giảm đòn bẩy. Tài sản thế chấp bao gồm bất động sản, phương tiện vận tải, tiền gửi ngân hàng và khoản phải thu từ hợp đồng.', 'Chi phí sản xuất kinh doanh dở dang chiếm tỷ trọng lớn nhất trong hàng tồn kho (70.36 tỷ/83.01 tỷ VND, tương đương ~85%). Đây là mức cao cần theo dõi chặt, đặc biệt trong bối cảnh ngành viễn thông có chu kỳ triển khai dự án dài. Tuy nhiên, thuyết minh cho biết không có hàng tồn kho ứ động, kém, mất phẩm chất. Hàng hóa (9.5 tỷ) và nguyên liệu (1.58 tỷ) có mức hợp lý. Tổng hàng tồn kho tăng từ 72.4 tỷ lên 83.0 tỷ, phản ánh hoạt động kinh doanh mở rộng.', 7, 'Công ty Cổ phần Viễn thông VTC có kết quả kinh doanh cải thiện đáng kể năm 2024 với lợi nhuận sau thuế 3.59 tỷ VND (tăng mạnh so với 310 triệu VND năm 2023). Doanh thu thuần đạt 236.6 tỷ VND, tăng 32%. Tuy nhiên, công ty tồn tại nhiều rủi ro: (1) Phụ thuộc lớn vào Tập đoàn VNPT (~65% doanh thu), (2) Nợ vay ngắn hạn cao với 36 tỷ VND vay cá nhân không ổn định, (3) Chi phí lãi vay 11.27 tỷ VND gây áp lực lên dòng tiền, (4) Cho vay ban lãnh đạo ~2.8 tỷ VND đặt câu hỏi về quản trị, (5) Chi phí SXKD dở dang 70.4 tỷ VND cần giám sát. Điểm tích cực là công ty đã giảm nợ từ 110.5 tỷ xuống 81 tỷ và dòng tiền hoạt động kinh doanh dương 43.5 tỷ VND. Kiểm toán viên đưa ra ý kiến chấp nhận toàn phần.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VTC_2025_consolidated', 'VTC', 2025, 'consolidated', 'Công ty có mối quan hệ kinh doanh mật thiết với Tập đoàn VNPT Group - cổ đông lớn nhất sở hữu 46,7% vốn. Doanh thu bán hàng cho các bên liên quan thuộc Tập đoàn VNPT chiếm tỷ trọng rất lớn (463,6 tỷ VNĐ/522,9 tỷ VNĐ tổng doanh thu ~89%). Các khoản phải thu từ các đơn vị thành viên VNPT Group lên tới hàng trăm tỷ VNĐ (VNPT-Net: 179,2 tỷ; Công ty CNTT VNPT: 87,8 tỷ). Công ty có khoản vay cá nhân 41,2 tỷ VNĐ từ các cá nhân (bao gồm nhân sự cấp cao như Nguyễn Đức Long). Các khoản tạm ứng cho cá nhân ban lãnh đạo (Nguyễn Đức Long: 490 triệu, Nguyễn Minh Vũ: 7,4 triệu). Có nhiều khoản phải thu/phải trả với các trung tâm kinh doanh VNPT trên toàn quốc. Mức độ tập trung giao dịch với một nhóm liên quan duy nhất (VNPT Group) tạo rủi ro phụ thuộc cao.', 'Nợ phải trả chiếm tỷ trọng cực lớn (529,4 tỷ VNĐ) so với vốn chủ sở hữu (81,0 tỷ VNĐ), tỷ lệ nợ/vốn chủ sở hữu ~6,5 lần. Nợ ngắn hạn chiếm 523,0 tỷ VNĐ (98,8% tổng nợ). Chi phí lãi vay năm 2025 đạt 11,3 tỷ VNĐ, tạo áp lực tài chính đáng kể. Có khoản vay cá nhân lãi suất cao 10-12%/năm trị giá 41,2 tỷ VNĐ. Nợ thuê tài chính từ Chailease lãi suất 10,70%-12,2%/năm. Dòng tiền hoạt động kinh doanh âm -138,8 tỷ VNĐ, cho thấy áp lực thanh khoản nghiêm trọng. Công ty phải tăng cường vay nợ để bù đắp dòng tiền kinh doanh âm. Nhiều khoản tiền gửi ngân hàng đã được cầm cố để đảm bảo khoản vay (Techcombank: 551,7 triệu; TPBank Hùng Vương: 2,2 tỷ). Tổng nợ phải trả ngắn hạn đáo hạn trong vòng 1 năm là 505,7 tỷ VNĐ trong khi tiền và tương đương tiền chỉ 33,6 tỷ VNĐ.', 'Tổng hàng tồn kho 155,9 tỷ VNĐ, tăng 88% so với đầu năm (83,0 tỷ VNĐ). Chi phí SXKD dở dang chiếm tỷ trọng rất lớn 126,4 tỷ VNĐ (81% tổng tồn kho), tăng 79,7% so với đầu năm. Hàng hóa thương mại tăng mạnh từ 9,5 tỷ lên 25,8 tỷ VNĐ. Công ty xác nhận không có hàng tồn kho ứ đọng, kém chất lượng. Tuy nhiên, tỷ trọng SXKD dở dang lớn cho thấy công ty đang triển khai nhiều dự án thi công công trình viễn thông, cần theo dõi tiến độ và khả năng thu hồi vốn. Không có dự phòng giảm giá hàng tồn kho.', 6, 'Công ty Cổ phần Viễn thông VTC ghi nhận tăng trưởng doanh thu mạnh 121% trong năm 2025, đạt 522,9 tỷ VNĐ, chủ yếu từ hợp đồng với Tập đoàn VNPT Group. Lợi nhuận sau thuế đạt 3,99 tỷ VNĐ (tăng 11%). Tuy nhiên, có nhiều điểm đáng lo ngại: (1) Dòng tiền hoạt động kinh doanh âm -138,8 tỷ VNĐ do phải thu thương mại tăng vọt từ 104,1 tỷ lên 341,8 tỷ VNĐ; (2) Nợ vay tăng mạnh 194% từ 81,1 tỷ lên 238,8 tỷ VNĐ; (3) Biên lợi nhuận gộp chỉ ~10% cho thấy biên mỏng trong hoạt động thương mại thiết bị viễn thông; (4) Tỷ lệ nợ/vốn chủ sở hữu ~6,5 lần; (5) Phụ thuộc lớn vào Tập đoàn VNPT Group (~89% doanh thu). Công ty có mối quan hệ mật thiết với Tập đoàn BVTVN - vừa tạo cơ hội kinh doanh ổn định vừa tạo rủi ro phụ thuộc. Nhà đầu tư cần đặc biệt lưu ý: tỷ lệ nợ ngắn hạn/tài sản ngắn hạn cao 89,4%, dòng tiền kinh doanh âm, và mức độ tập trung khách hàng cao.'),
('VTC_2023_consolidated', 'VTC', 2023, 'consolidated', 'Rủi ro CỰC KỲ CAO. Công ty có mạng lưới giao dịch với bên liên quan rất phức tạp: (1) Các khoản phải thu cá nhân lớn từ ban lãnh đạo: Lê Xuân Tiến (Chủ tịch HĐQT) 995 triệu, Bùi Văn Bằng (Tổng GĐ) 552 triệu, Trần Văn Mua (P.TGĐ) 577 triệu, Nguyễn Minh Vũ (P.TGĐ) 369 triệu, Nguyễn Đức Long (P.TGĐ) 385 triệu, Lê Thị Thanh (TV HĐQT) 470 triệu; (2) Quyết định quản trị bất thường: HĐQT, BKS, BĐH thống nhất hoàn lại 80% tiền lương năm 2023, chi phí lương chủ chốt giảm từ 8,4 tỷ xuống 1,5 tỷ cho thấy công ty gặp khó khăn tài chính nghiêm trọng; (3) Công ty con CP Đầu tư và PT Công nghệ thông minh (60%) báo lỗ 599 triệu và không trích thù lao HĐQT, BKS theo Nghị quyết ĐHĐCD; (4) Giao dịch bán hàng với hàng chục đơn vị thuộc Tập đoàn VNPT chiếm tỷ trọng doanh thu lớn.', 'Áp lực nợ vay RẤT CAO. Tổng nợ vay và thuê tài chính: 110,5 tỷ VND (nợ ngắn hạn 108,3 tỷ, nợ dài hạn 2,3 tỷ). Chi phí lãi vay 10,2 tỷ VND so với lợi nhuận thuần từ hoạt động kinh doanh chỉ 1,9 tỷ. Có 32,4 tỷ vay cá nhân với lãi suất 10-12%/năm, thời hạn rất ngắn (1-3 tháng). Tài sản thế chấp bao gồm bất động sản, phương tiện vận tải, hàng tồn kho, khoản phải thu và tiền gửi ngân hàng. Dòng tiền từ hoạt động kinh doanh âm 23,2 tỷ cho thấy công ty phải đi vay mới để trả nợ cũ.', 'Tồn kho rất lớn 72,4 tỷ VND (tương đương 40% doanh thu thuần). Chi phí SXKD dở dang chiếm 60,2 tỷ - chủ yếu từ hoạt động lắp đặt - cần theo dõi khả năng thu hồi. Hàng hóa giảm mạnh từ 26,3 tỷ xuống 8,8 tỷ cho thấy hàng hóa khó tiêu thụ hoặc đã bán giảm giá. Đa số hàng tồn kho dùng để thế chấp đảm bảo khoản vay. Không có dự phòng giảm giá hàng tồn kho.', 8, 'Doanh thu sụt giảm mạnh 31% (từ 261,3 tỷ xuống 179,1 tỷ). Biên LN gộp cải thiện nhẹ 21,8% vs 16,1%. Tuy nhiên lợi nhuận sau thuế của CĐKS giảm 62% (từ 521 triệu xuống 909 triệu - trong đó lợi nhuận sau thuế lợi ích CĐKS là 309 triệu). Chi phí lãi vay tăng 26% (8,1 tỷ → 10,2 tỷ). Nợ ngắn hạn tăng 18%. Công ty phải hoàn lương hiệu suất ban lãnh đạo, hủy trích thù lao cho công ty con, cho thấy áp lực tài chính nghiêm trọng. Dòng tiền hoạt động kinh doanh âm 23,2 tỷ - phải dựa vào hoạt động tài chính (vay mới). Công ty con báo lỗ. Triển vọng đầu tư BI QUAN: doanh thu suy giảm, đòn bẩy tài chính cao, dòng tiền âm, rủi ro quản trị lớn.'),
('VTM_2015_consolidated', 'VTM', 2015, 'consolidated', 'Công ty có tỷ trọng giao dịch nội bộ Tập đoàn TKV rất lớn: doanh thu vận chuyển nội bộ 325.964 tỷ VND (chiếm ~95% doanh thu vận chuyển), mua vật tư nội bộ 43.728 tỷ VND. Giao dịch tập trung chủ yếu với các công ty than và đơn vị thành viên Tập đoàn. Không phát hiện giao dịch bất thường (cho vay không lãi suất, mua bán chênh lệch lớn) nhưng mức độ phụ thuộc vào Tập đoàn mẹ là đáng lo ngại do hơn 95% doanh thu đến từ nội bộ Tập đoàn.', 'Tổng nợ vay và thuê tài chính là 109.379 tỷ VND (vốn chủ sở hữu chỉ 33.951 tỷ VND), tỷ lệ nợ/vốn chủ sở hữu ~3,2 lần. Chi phí lãi vay năm 2015 là 10.447 tỷ VND. Phần lớn TSCĐ hữu hình (giá trị còn lại 114.266 tỷ VND) đã được dùng làm tài sản thế chấp cho các khoản vay. Dòng tiền hoạt động kinh doanh thuần 53.299 tỷ VND đủ để chi trả lãi vay. Áp lực trả nợ gốc ngắn hạn 52.959 tỷ VND trong năm tới là đáng kể.', 'Hàng tồn kho chủ yếu là nguyên vật liệu (6.254 tỷ VND) và công cụ dụng cụ (27 triệu VND), không có dự phòng giảm giá. Tốc độ luân chuyển nhanh do đặc thù ngành dịch vụ vận tải. Chi phí XDCB dở dang giảm mạnh từ 26.161 tỷ xuống 2.886 tỷ VND (hoàn thành và chuyển sang TSCĐ). Các dự án xây dựng dở dang chủ yếu là nhà chờ xe công nhân và mua xe ô tô, chưa có dấu hiệu ứ đọng.', 5, 'Công ty Cổ phần Vận tải và Đưa đón thợ mỏ - Vinacomin hoạt động trong lĩnh vực vận tải phục vụ ngành than, với 95% doanh thu đến từ Tập đoàn TKV và các đơn vị thành viên. Công ty có tỷ lệ nợ vay cao (3,2 lần vốn chủ sở hữu) với tổng nợ 109.379 tỷ VND, áp lực lãi vay 10,4 tỷ/năm. Tuy nhiên, biên lợi nhuận gộp đạt 13,88%, lợi nhuận sau thuế 4,2 tỷ VND và dòng tiền hoạt động kinh doanh 53,3 tỷ VND đảm bảo khả năng chi trả lãi vay. Rủi ro chính là sự phụ thuộc lớn vào Tập đoàn mẹ và tỷ lệ đòn bẩy tài chính cao. Công ty đã phát hành thêm cổ phiếu tăng vốn từ 16,8 tỷ lên 32,8 tỷ VND trong năm 2015.'),
('VTC_2022_consolidated', 'VTC', 2022, 'consolidated', 'Công ty có giao dịch cho vay với các thành viên Hội đồng quản trị và Ban điều hành, nhưng không có lãi suất được công bố rõ ràng. Giao dịch mua bán với các đơn vị trong Tập đoàn VNPT theo giá thỏa thuận, không có dấu hiệu bất thường lớn.', 'Nợ vay ngắn hạn chiếm tỷ trọng cao, với tổng số 99.7 tỷ VND, áp lực trả nợ lớn. Tài sản đảm bảo bao gồm bất động sản, xe cộ, tiền gửi. Cần theo dõi khả năng thanh toán.', 'Hàng tồn kho lớn 65.8 tỷ VND, trong đó chi phí sản xuất kinh doanh dở dang 38.2 tỷ VND (chủ yếu lắp đặt). Không có dự phòng giảm giá. Rủi ro tồn kho ở mức trung bình.', 5, 'Doanh thu tăng 91% so với năm trước do hoạt động sản xuất kinh doanh phục hồi sau Covid-19, nhưng lợi nhuận gộp giảm do chi phí nguyên vật liệu tăng. Chi phí lãi vay tăng 2.7 tỷ VND do vay thêm để thực hiện dự án. Công ty có nợ ngắn hạn lớn, cần quản lý vốn lưu động hiệu quả. Triển vọng phụ thuộc vào khả năng thu hồi công nợ và kiểm soát chi phí.'),
('VTC_2021_consolidated', 'VTC', 2021, 'consolidated', 'Công ty có giao dịch với các bên liên quan bao gồm thành viên quản lý chủ chốt và các công ty trong Tập đoàn Bưu chính Viễn thông Việt Nam. Các giao dịch này chủ yếu là thương mại thông thường, không có dấu hiệu bất thường như cho vay không lãi suất hay chênh lệch giá lớn.', 'Nợ ngắn hạn của công ty khá lớn, chủ yếu từ ngân hàng và cá nhân, với lãi suất rõ ràng. Công ty có tài sản thế chấp để đảm bảo khoản vay, nhưng áp lực nợ vay vẫn tồn tại do nợ đến hạn trong ngắn hạn.', 'Hàng tồn kho bao gồm nguyên liệu, thành phẩm và chi phí SXKD dở dang. Công ty cho biết không có hàng tồn kho ứ động hay mất phẩm chất, nhưng chi phí SXKD dở dang lớn cần được theo dõi để đảm bảo tiến độ dự án.', 5, 'Công ty chịu ảnh hưởng của dịch Covid-19 nên doanh thu giảm trong năm 2021. Tuy nhiên, công ty vẫn duy trì lợi nhuận và có kế hoạch chia cổ tức. Nợ vay ngắn hạn cao nhưng được kiểm soát bằng tài sản thế chấp. Cơ cấu quản trị đầy đủ với Hội đồng quản trị, Ban Kiểm soát và Ban Điều hành. Triển vọng phụ thuộc vào sự phục hồi của ngành viễn thông và quản lý nợ.'),
('VTC_2020_consolidated', 'VTC', 2020, 'consolidated', 'Công ty có giao dịch với công ty con (Công ty CP Đầu tư và Phát triển Công Nghệ Thông Minh, sở hữu 60%) với khoản nhận cổ tức 3,6 tỷ VND trong năm 2020. Công ty không phát sinh giao dịch bán hàng/dịch vụ cho các bên liên quan. Các khoản phải trả ngắn hạn cho thành viên HĐQT và Ban Điều hành tồn tại cuối kỳ với tổng số dư ~88,9 triệu VND (quy mô nhỏ). Trong năm, có phát sinh lớn các khoản tạm ứng cho cá nhân quản lý (Bùi Văn Bằng: 7,577 tỷ, Nguyễn Minh Vũ: 11,47 tỷ, Trần Văn Mua: 9,9 tỷ, Nguyễn Đức Long: 3,63 tỷ) nhưng tất cả đã được thanh toán trong kỳ, không còn dư cuối kỳ. Nhìn chung, các giao dịch với bên liên quan ở mức kiểm soát được, không có dấu hiệu bất thường đáng kể.', 'Công ty có áp lực nợ vay ngắn hạn đáng kể với tổng vay ngắn hạn cuối kỳ 104,4 tỷ VND (giảm so với đầu kỳ 148,3 tỷ), chiếm ~30% tổng tài sản. Các khoản vay chủ yếu từ ngân hàng MB (29,1 tỷ), Techcombank (43,9 tỷ) và cá nhân (31,4 tỷ, lãi suất 10%/năm). Tài sản đảm bảo bao gồm tiền gửi ngân hàng, xe ô tô, bất động sản, hàng hóa và quyền đòi nợ. Công ty không có nợ dài hạn. Chi phí lãi vay trong năm là 9,77 tỷ VND, chiếm tỷ trọng đáng kể trong lợi nhuận gộp. Cần theo dõi khả năng trả nợ khi các khoản vay đáo hạn ngắn hạn.', 'Tổng hàng tồn kho cuối kỳ là 48,2 tỷ VND (tăng nhẹ so với đầu kỳ 46,8 tỷ). Công ty xác nhận không có hàng tồn kho ứ động, kém chất lượng hay mất phẩm chất. Dự phòng giảm giá hàng tồn kho đã được hoàn nhập toàn bộ 893 triệu VND trong năm. Đa số hàng tồn kho được dùng để thế chấp đảm bảo khoản vay ngân hàng. Chi phí SXKD dở dang 12 tỷ VND chủ yếu từ hoạt động lắp đặt cần theo dõi tiến độ hoàn thành.', 4, 'Công ty CP Viễn thông VTC chịu ảnh hưởng tiêu cực từ đại dịch COVID-19 với doanh thu giảm mạnh từ 598 tỷ xuống 379 tỷ VND (giảm 36,7%). Biên lợi nhuận gộp giảm từ 7,9% xuống 11,7% (năm trước 7,9% nhưng lợi nhuận gộp tuyệt đối giảm). Công ty vẫn đạt lợi nhuận sau thuế 11,6 tỷ VND, tăng nhẹ so với năm trước 11,4 tỷ. Dòng tiền hoạt động kinh doanh dương 29,8 tỷ nhưng không đủ bù đắp dòng tiền đầu tư và tài chính âm, dẫn đến tiền mặt giảm mạnh từ 42,9 tỷ xuống 16,9 tỷ. Nợ vay ngắn hạn vẫn ở mức cao (104,4 tỷ). Công ty có hoạt động đầu tư vào công ty con mang lại cổ tức ổn định (3,6 tỷ/năm). Triển vọng phụ thuộc vào khả năng phục hồi hậu COVID-19 và quản lý dòng tiền, nợ vay hiệu quả.'),
('VTC_2019_consolidated', 'VTC', 2019, 'consolidated', 'Công ty có giao dịch với các bên liên quan, chủ yếu là tạm ứng, thù lao cho thành viên HĐQT, BKS và BĐH, cũng như giao dịch mua bán với Công ty CP Công nghệ Tích hợp (ITE). Các giao dịch này có quy mô không lớn, không có dấu hiệu bất thường rõ ràng, nhưng cần lưu ý về tính minh bạch và điều kiện giao dịch.', 'Nợ ngắn hạn chiếm tỷ trọng cao, với tổng số nợ vay ngắn hạn khoảng 148 tỷ VNĐ, bao gồm vay ngân hàng và vay cá nhân. Công ty có tài sản thế chấp như tiền gửi, xe ô tô, bất động sản và quyền đòi nợ. Áp lực trả nợ ngắn hạn lớn, nhưng Công ty có dòng tiền kinh doanh dương trong năm nay để hỗ trợ.', 'Hàng tồn kho có dự phòng giảm giá 972 triệu VNĐ, cho thấy một phần hàng tồn kho có khả năng bị lỗi thời hoặc kém phẩm chất. Chi phí SXKD dở dang cao (29.8 tỷ VNĐ) chủ yếu từ hoạt động lắp đặt, cần theo dõi tiến độ và hiệu quả.', 4, 'Công ty có lợi nhuận sau thuế tăng trưởng, nhưng nợ vay ngắn hạn cao và hàng tồn kho có dự phòng. Dòng tiền từ hoạt động kinh doanh cải thiện, nhưng cần quản lý chặt chẽ nợ và tồn kho. Triển vọng phụ thuộc vào khả năng thu hồi nợ và hiệu quả kinh doanh.'),
('VTC_2018_consolidated', 'VTC', 2018, 'consolidated', 'Công ty có các giao dịch trọng yếu với công ty con (cho vay, trả nợ, nhận cổ tức) và bên liên quan ITE (mua bán hàng hóa). Các giao dịch này có giá trị lớn nhưng được công bố chi tiết, chưa thấy dấu hiệu bất thường về giá chuyển nhượng hay điều kiện giao dịch bất lợi.', 'Nợ ngắn hạn tăng mạnh từ 129.5 tỷ lên 179 tỷ đồng, chủ yếu từ vay ngân hàng và cá nhân. Tài sản đảm bảo đa dạng (ô tô, tiền gửi, bất động sản). Áp lực trả nợ ngắn hạn cao nhưng dòng tiền từ hoạt động kinh doanh âm, cần theo dõi khả năng tái tài trợ.', 'Hàng tồn kho tăng 45% từ 37.8 tỷ lên 54.9 tỷ đồng, trong đó chi phí SXKD dở dang chiếm tỷ trọng lớn (24.5 tỷ). Dự phòng giảm giá hàng tồn kho được hoàn nhập toàn bộ, cho thấy đánh giá tích cực về khả năng tiêu thụ. Tuy nhiên, cần theo dõi tiến độ hoàn thành các dự án dở dang.', 5, 'Công ty có doanh thu tăng 22%, lợi nhuận gộp tăng 86% cho thấy hoạt động kinh doanh cải thiện. Tuy nhiên, nợ vay tăng mạnh, dòng tiền hoạt động kinh doanh âm (-49.2 tỷ). Hàng tồn kho và phải thu tăng cao ảnh hưởng đến thanh khoản. Công ty có giao dịch với bên liên quan nhưng minh bạch. Điểm rủi ro quản trị trung bình.'),
('VTC_2017_consolidated', 'VTC', 2017, 'consolidated', 'Công ty có các giao dịch đáng kể với công ty con (Công ty TNHH Đầu tư và Phát triển Công nghệ Thông minh - STID) bao gồm cho vay, nhận vay, mua bán hàng hóa và chia lợi nhuận. Các giao dịch này được thực hiện theo điều kiện thị trường và có ghi nhận lãi vay (7.8%/năm). Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn bất thường.', 'Nợ vay ngắn hạn tăng mạnh từ 44.1 tỷ đồng lên 129.5 tỷ đồng, chủ yếu từ ngân hàng Quân đội (92.8 tỷ) và vay cá nhân (30 tỷ). Công ty có tài sản thế chấp là xe ô tô, máy móc và tiền gửi ngân hàng. Áp lực nợ vay ngắn hạn cao, cần theo dõi khả năng thanh toán và tái cơ cấu nợ.', 'Hàng tồn kho tăng từ 36.5 tỷ lên 40.0 tỷ, trong đó chi phí SXKD dở dang chiếm tỷ trọng lớn (18.1 tỷ). Công ty đã trích lập dự phòng giảm giá hàng tồn kho 2.19 tỷ cho nguyên vật liệu và hàng hóa. Hàng gửi đi bán tăng mạnh (15.6 tỷ) cần theo dõi khả năng tiêu thụ.', 5, 'Công ty đạt mức tăng trưởng doanh thu ấn tượng (53.6%), lợi nhuận sau thuế tăng 56.7%. Tuy nhiên, nợ vay ngắn hạn tăng gấp 3 lần, gây áp lực lên thanh khoản. Hàng tồn kho và phải thu khách hàng tăng mạnh, cần quản lý hiệu quả. Công ty có quan hệ đầu tư với công ty con và phát sinh giao dịch nội bộ đáng kể. Sức khỏe tài chính ở mức trung bình, cần chú ý quản lý dòng tiền và cơ cấu nợ.'),
('VTC_2016_parent', 'VTC', 2016, 'parent', 'Công ty có giao dịch đáng kể với Công ty con STID (60%): cho vay 5,5 tỷ đồng với lãi suất 8,8%/năm, phát sinh các khoản phải trả thương mại và chi phí dịch vụ. Ngoài ra còn có khoản cho vay 280,6 triệu với lãi suất 10%/năm cho Công ty Cổ phần Công nghệ Tích Hợp. Các giao dịch này được thực hiện với lãi suất thị trường, không có dấu hiệu bất thường rõ ràng. Công ty nhận cổ tức từ công ty con 1,5 tỷ và từ công ty liên kết 480 triệu trong năm.', 'Áp lực nợ vay rất cao. Tổng nợ vay ngắn hạn chiếm 44,1 tỷ VNĐ (chiếm 81% tổng nợ phải trả). Công ty vay từ nhiều nguồn đa dạng: ngân hàng BIDV (10,8 tỷ, lãi 7%/năm), MB (8,5 tỷ, lãi 7,5-8%/năm), công ty con STID (5,5 tỷ, lãi 8,8%/năm) và đặc biệt vay cá nhân lên đến 19 tỷ (lãi 10%/năm) cho thấy khả năng huy động vốn ngân hàng bị hạn chế. Chi phí lãi vay năm 2016 là 6,057 tỷ đồng, chiếm tỷ trọng lớn trong chi phí tài chính. Tài sản thế chấp bao gồm tiền gửi có kỳ hạn và ô tô. Tỷ lệ nợ/vốn chủ sở hữu ~2:1.', 'Hàng tồn kho tăng mạnh từ 9,7 tỷ lên 36,5 tỷ đồng (tăng 276%). Đáng chú ý, hàng mua đang đi đường chiếm 14,8 tỷ và chi phí SXKD dở dang chiếm 12,3 tỷ. Dự án xây dựng nhà xưởng tại khu Công nghệ cao trị giá 700 triệu đang tạm ngưng triển khai, có nguy cơ trở thành tài sản kém hiệu quả. Không có dự phòng giảm giá hàng tồn kho nào được trích lập.', 6, 'VTC Telecom ghi nhận kết quả kinh doanh tích cực năm 2016 với doanh thu tăng 399% và lợi nhuận trước thuế tăng 121% so với năm 2015. Tuy nhiên, dòng tiền hoạt động kinh doanh âm 28,2 tỷ đồng do phải thu và tồn kho tăng mạnh, cho thấy chất lượng lợi nhuận chưa cao. Công ty có cấu trúc tài chính đòn bẩy cao với nợ vay lớn, đặc biệt nợ vay cá nhân chiếm tỷ trọng đáng kể (19 tỷ) cho thấy hạn chế trong tiếp cận vốn ngân hàng. Hàng tồn kho tăng đột biến cần được theo dõi chặt chẽ. Dự án xây dựng dở dang tạm ngưng là điểm rủi ro. Công ty có mối quan hệ kinh doanh với công ty con STID nhưng không có giao dịch bất thường nổi bật. Năng lực thanh toán ngắn hạn cần được cải thiện.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VTC_2016_consolidated', 'VTC', 2016, 'consolidated', 'Chỉ có giao dịch thù lao với ban giám đốc, không có giao dịch bất thường với các bên liên quan khác.', 'Nợ vay ngắn hạn lớn, áp lực thanh toán cao với lãi suất từ 7% đến 10%/năm. Tài sản thế chấp bao gồm tiền gửi và ô tô.', 'Tồn kho tăng mạnh, dự án xây dựng dở dang tạm ngưng, có nguy cơ ứ đọng vốn.', 4, 'Doanh thu tăng trưởng mạnh nhưng nợ vay cao, cần giám sát thanh khoản. Lợi nhuận khả quan nhưng rủi ro tài chính đáng kể.'),
('VTC_2015_consolidated', 'VTC', 2015, 'consolidated', 'Doanh nghiệp có giao dịch với công ty con STID bao gồm cho vay ngắn hạn (2 tỷ VND), chi phí lãi vay (89.8 triệu VND) và nhận lợi nhuận chia (1.5 tỷ VND). Các giao dịch này được ghi nhận công khai và giá trị không quá lớn so với tổng tài sản, nhưng cần lưu ý mối quan hệ sở hữu 60% và giao dịch tài chính nội bộ.', 'Tổng nợ vay 11.17 tỷ VND, trong đó nợ ngắn hạn chiếm phần lớn (9.28 tỷ VND). Áp lực trả nợ ngắn hạn cao. Tài sản thế chấp bao gồm xe ô tô và quyền đòi nợ hình thành trong tương lai. Công ty có tỷ lệ nợ trên vốn chủ sở hữu thấp (2.68%) nhưng cơ cấu nợ ngắn hạn là rủi ro thanh khoản.', 'Hàng tồn kho tăng mạnh từ 11.4 tỷ lên 16.1 tỷ VND, chủ yếu do chi phí SXKD dở dang tăng vọt từ 0.94 tỷ lên 9.82 tỷ VND. Điều này cho thấy có nhiều dự án/dịch vụ dở dang, tiềm ẩn rủi ro chuyển đổi thành tiền mặt nếu không hoàn thành đúng tiến độ.', 4, 'Doanh nghiệp có doanh thu ổn định quanh mức 108.7 tỷ VND, lợi nhuận sau thuế tăng trưởng tốt 43.7% đạt 9.63 tỷ VND. Tuy nhiên, cơ cấu nợ ngắn hạn cao, tồn kho dở dang tăng mạnh là những rủi ro cần giám sát. Công ty có mối quan hệ với công ty con và liên kết nhưng giao dịch minh bạch. Điểm mạnh là tỷ suất lợi nhuận gộp cải thiện (30%) và công ty đang trong quá trình áp dụng chuẩn mực kế toán mới.'),
('VTB_2025_consolidated', 'VTB', 2025, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là chi trả cổ tức cho công ty mẹ và nhận tiền góp vốn từ công ty cùng công ty mẹ cho hoạt động hợp tác kinh doanh. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Doanh nghiệp không có nợ dài hạn và đã trả gần hết nợ ngắn hạn. Áp lực nợ vay thấp, khả năng thanh toán tốt với lượng tiền mặt và đầu tư ngắn hạn dồi dào.', 'Hàng tồn kho (đặc biệt là hàng hóa) có dự phòng giảm giá giá trị lớn, cho thấy rủi ro hàng tồn kho chậm luân chuyển hoặc mất giá. Dự án xây dựng VTB Green Building đang gặp vướng mắc pháp lý, có thể gây chậm trễ và tăng chi phí.', 3, 'Doanh thu và lợi nhuận sau thuế tăng trưởng tốt. Nợ vay ở mức thấp, thanh khoản an toàn. Điểm rủi ro chính nằm ở hàng tồn kho có dự phòng lớn và dự án xây dựng dở dang tiềm ẩn rủi ro pháp lý. Quản trị doanh nghiệp không có dấu hiệu xung đột lợi ích nghiêm trọng.'),
('VTB_2025_parent', 'VTB', 2025, 'parent', 'Công ty có giao dịch lớn với các công ty con, đặc biệt doanh thu bán hàng cho Công ty CP Công nghệ Thông tin VTB chiếm tỷ trọng lớn (21.884 tỷ/128.184 tỷ doanh thu). Các khoản phải thu từ công ty con lên đến 17.362 tỷ, trong đó khoản phải thu từ Công ty CP Vitek - VTB Hà Nội (8.969 tỷ) đã bị trích lập dự phòng gần như toàn bộ do quá hạn trên 3 năm. Công ty cho công ty con vay và sau đó phạt lãi quá hạn, đồng thời hỗ trợ lãi quá hạn cho cùng một công ty con - đây là giao dịch ngược chiều đáng chú ý.', 'Áp lực nợ vay thấp, Công ty đã tất toán toàn bộ nợ vay ngắn hạn trong năm 2025. Không có nợ vay dài hạn. Nguồn vốn chủ yếu từ vốn chủ sở hữu (185.674 tỷ). Tuy nhiên, Công ty có khoản trả trước thuê đất dài hạn 18.215 tỷ cho Công ty TNHH MTV Dịch vụ Công ích Quận 2 mà chưa ký hợp đồng chính thức, tiềm ẩn rủi ro về mặt pháp lý và giá trị.', 'Hàng tồn kho tăng từ 13.332 tỷ lên 16.156 tỷ (tăng 21%). Dự phòng giảm giá hàng tồn kho giữ nguyên ở mức 2.000 tỷ. Dự án VTB Green Building trị giá 9.330 tỷ đã treo nhiều năm chưa triển khai do vướng mắc pháp lý, đây là khoản đầu tư dở dang có rủi ro cao về khả năng thu hồi giá trị.', 5, 'Công ty hoạt động kinh doanh có lãi tốt với lợi nhuận sau thuế 16.764 tỷ (tăng 44,5% so với năm trước). Biên lợi nhuận gộp đạt 53,4% cho thấy hiệu quả sản xuất kinh doanh cao. Tuy nhiên, công ty có rủi ro tập trung vào giao dịch với bên liên quan (công ty con), đặc biệt khoản phải thu quá hạn lớn từ Công ty CP Vitek - VTB Hà Nội. Dự án VTB Green Building treo nhiều năm là điểm cần theo dõi. Về cơ bản, công ty có sức khỏe tài chính tốt với tỷ lệ nợ thấp, dòng tiền kinh doanh dương mạnh (21.237 tỷ), và thanh khoản ổn định.'),
('VTB_2024_parent', 'VTB', 2024, 'parent', 'Doanh nghiệp có giao dịch đáng kể với các công ty con, đặc biệt khoản phải thu khách hàng lớn từ Công ty CP Vitek - VTB Hà Nội (8,9 tỷ VND) với dự phòng phải thu khó đòi cao (8,3 tỷ VND), cho thấy rủi ro tín dụng nội bộ. Giao dịch mua bán hàng hóa với công ty con diễn ra thường xuyên, cần giám sát tính thị trường.', 'Áp lực nợ vay thấp với nợ ngắn hạn chỉ hơn 2,8 tỷ VND, chiếm tỷ trọng nhỏ trong tổng tài sản. Công ty có tài sản thế chấp theo hợp đồng bảo đảm cho khoản vay ngân hàng. Dòng tiền hoạt động kinh doanh dương mạnh (15,7 tỷ VND năm 2024) đảm bảo khả năng trả nợ.', 'Dự phòng giảm giá hàng tồn kho tăng từ 1 tỷ lên 2 tỷ VND, đặc biệt dự phòng cho nguyên vật liệu tăng mạnh (từ 202 triệu lên 718 triệu VND). Dự án xây dựng dở dang VTB Green Building gặp vướng mắc pháp lý, chưa rõ tiến độ hoàn thành, tiềm ẩn rủi ro chậm tiến độ và lãng phí vốn.', 6, 'Sức khỏe tài chính ổn định với biên lợi nhuận gộp cao (~57%), dòng tiền kinh doanh tích cực, và tỷ lệ nợ thấp. Tuy nhiên, tồn tại rủi ro từ quan hệ kinh tế chéo với các công ty con, đặc biệt khoản phải thu khó đòi lớn tại Vitek - VTB Hà Nội. Dự án BĐS dở dang gặp vướng mắc pháp lý là điểm trừ. Điểm sáng là doanh thu tăng trưởng tốt (9.6%) và lợi nhuận sau thuế tăng (5.8%). Công ty có vị thế thanh toán tốt với tiền và tương đương tiền tăng mạnh.'),
('VTB_2024_consolidated', 'VTB', 2024, 'consolidated', 'Giao dịch chủ yếu là thanh toán cổ tức cho công ty mẹ, không có giao dịch bất thường rõ ràng, nhưng công ty mẹ có ảnh hưởng đáng kể.', 'Nợ vay ngắn hạn ở mức thấp, chủ yếu từ ngân hàng, áp lực nợ vay không cao.', 'Hàng tồn kho có dự phòng giảm giá, cho thấy rủi ro suy giảm giá trị, đặc biệt với thành phẩm và hàng hóa.', 5, 'Công ty có tình hình tài chính ổn định, lợi nhuận tăng trưởng, nợ vay thấp, nhưng rủi ro tồn kho và phụ thuộc vào công ty mẹ.'),
('VTB_2023_consolidated', 'VTB', 2023, 'consolidated', 'Công ty có giao dịch với công ty mẹ (Tổng Công ty Cổ phần Điện tử và Tin học Việt Nam) chủ yếu là chi trả cổ tức. Số dư phải trả với công ty mẹ cuối năm 2023 là 3.327.480.000 đồng (tăng mạnh so với đầu năm 654.960.000 đồng). Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch giá với bên liên quan.', 'Áp lực nợ vay thấp. Tổng nợ vay ngắn hạn chỉ 1.760.000.000 đồng, chiếm tỷ trọng rất nhỏ trong tổng tài sản (dưới 1%). Công ty có nguồn tiền gửi có kỳ hạn lớn (55.300.000.000 đồng) và dòng tiền hoạt động kinh doanh thuần dương mạnh (26.159.670.270 đồng), đảm bảo khả năng thanh toán tốt. Tài sản thế chấp theo Hợp đồng Cấp tín dụng với Vietcombank.', 'Hàng tồn kho giảm nhẹ so với đầu năm (từ 34.416 tỷ xuống 33.064 tỷ). Dự phòng giảm giá tăng từ 1.166 tỷ lên 1.524 tỷ, cho thấy một phần hàng tồn kho có nguy cơ giảm giá. Dự án xây dựng VTB Green Building (9.444 tỷ đồng) đang bị vướng mắc pháp lý, chưa có tiến triển từ đầu năm, tiềm ản rủi ro vốn bị đọng.', 4, 'Công ty Viettronics Tân Bình có sức khỏe tài chính ổn định với tỷ suất lợi nhuận gộp cao (63,1%), nợ vay thấp và dòng tiền kinh doanh dương mạnh. Tuy nhiên, doanh thu giảm mạnh 55% so với năm 2022, lợi nhuận sau thuế giảm 52%. Công ty có khoản đầu tư xây dựng dở dang lớn (9.444 tỷ đồng) bị vướng pháp lý, đầu tư vào công ty liên kết mới (17.500 tỷ đồng) cần theo dõi hiệu quả. Lợi ích cổ đông không kiểm soát bị lỗ trong năm 2023 (-93.914.149 đồng). Công ty duy trì chính sách chi trả cổ tức đều đặn.'),
('VTB_2022_consolidated', 'VTB', 2022, 'consolidated', 'Công ty có giao dịch với công ty mẹ (Tổng Công ty Cổ phần Điện tử và Tin học Việt Nam) chủ yếu là phân phối cổ tức và số dư phải trả khác, không phát hiện giao dịch bất thường đáng kể.', 'Công ty có nợ vay ngắn hạn 8 tỷ VND, được đảm bảo bằng tiền gửi ngân hàng. Tỷ lệ nợ trên tổng tài sản thấp, áp lực nợ vay không cao.', 'Hàng tồn kho đã giảm mạnh, công ty đã trích lập dự phòng giảm giá. Dự án xây dựng dở dang (VTB Green Building) trị giá 9.4 tỷ chưa có thông tin tiến độ, có thể tiềm ẩn rủi ro.', 3, 'Công ty có kết quả kinh doanh tăng trưởng mạnh (lợi nhuận sau thuế 22.4 tỷ, tăng so với 7.6 tỷ năm trước), cơ cấu tài sản an toàn, nợ vay thấp, hàng tồn kho được kiểm soát. Tuy nhiên, doanh thu giảm và dự án xây dựng dở dang cần theo dõi. Triển vọng trung bình.'),
('VTB_2023_parent', 'VTB', 2023, 'parent', 'Có giao dịch lớn với các công ty con và công ty mẹ, bao gồm bán hàng, mua hàng, hỗ trợ lãi và chia cổ tức. Không phát hiện giao dịch bất thường rõ ràng như cho vay không lãi suất, nhưng cần theo dõi các khoản phải thu với công ty con, đặc biệt Công ty Vitek - VTB Hà Nội có dự phòng phải thu lớn.', 'Nợ vay ngắn hạn thấp, chỉ 1,26 tỷ VND, áp lực nợ không cao. Tài sản thế chấp theo hợp đồng tín dụng với Vietcombank, nhưng lãi suất linh hoạt theo Giấy nhận nợ.', 'Hàng tồn kho có dự phòng giảm giá tăng so với năm trước, phản ánh nguy cơ giảm giá trị. Dự án xây dựng VTB Green Building đang bị đình trệ do vấn đề pháp lý, có nguy cơ ứ đọng vốn.', 4, 'Doanh nghiệp duy trì lợi nhuận gộp cao (71,5%) nhưng lợi nhuận sau thuế giảm mạnh so với năm trước. Tình hình tài cơ bản ổn định với tỷ lệ nợ thấp và dòng tiền hoạt động kinh doanh dương. Tuy nhiên, rủi ro đến từ hàng tồn kho, dự án xây dựng dở dang và giao dịch bên liên quan cần giám sát. Triển vọng trung lập.'),
('VTB_2022_parent', 'VTB', 2022, 'parent', 'Doanh nghiệp có nhiều giao dịch với các công ty con (Công ty Cổ phần Công nghệ Thông tin VTB, Công ty Cổ phần Vitek - VTB Hà Nội, Công ty Cổ phần Thương mại JS VTB) và công ty mẹ (Tổng Công ty Cổ phần Điện tử và Tin học Việt Nam). Các khoản phải thu từ bên liên quan lớn (gần 27 tỷ VND tại ngày 31/12/2022), có phát sinh lãi quá hạn và hỗ trợ lãi cho công ty con. Mặc dù giao dịch là thương mại nhưng quy mô lớn và tập trung vào nhóm công ty con, mẹ tạo rủi ro về tính độc lập và khả năng thu hồi công nợ.', 'Doanh nghiệp có nợ vay ngắn hạn 8 tỷ VND từ Ngân hàng TMCP Việt Nam Thương Tín với hạn mức tín dụng 12.5 tỷ, đáo hạn 30/06/2023, lãi suất thỏa thuận, bảo đảm bằng tiền gửi tại chính ngân hàng này. Áp lực nợ vay không cao do tổng nợ phải trả chỉ chiếm khoảng 16% tổng nguồn vốn và công ty có tài sản ngắn hạn lớn.', 'Hàng tồn kho giảm mạnh từ 29.8 tỷ xuống 21.1 tỷ (giảm 29%) so với đầu năm, chủ yếu do giảm nguyên vật liệu và thành phẩm. Công ty đã trích lập dự phòng giảm giá hàng tồn kho 480 triệu VND cho các mặt hàng có sự suy giảm giá trị. Dự án xây dựng dở dang (VTB Green Building) trị giá 9.4 tỷ VND không thay đổi so với đầu năm, cho thấy dự án có thể bị ứ đọng.', 6, 'Sức khỏe tài chính của doanh nghiệp cải thiện đáng kể trong năm 2022 với lợi nhuận sau thuế tăng gấp 3 lần (24.7 tỷ VND) so với năm trước, biên lợi nhuận gộp đạt mức cao (~59.4%). Doanh thu giảm 26% nhưng giá vốn giảm mạnh hơn (55%) nhờ quản lý chi phí hiệu quả. Nợ vay thấp, thanh khoản tốt (tiền và tương đương tiền tăng). Tuy nhiên, doanh nghiệp phụ thuộc nhiều vào giao dịch với các công ty con, mẹ và có khoản phải thu lớn từ bên liên quan, tiềm ẩn rủi ro về quản trị và dòng tiền. Dự án xây dựng dở dang cần được theo dõi tiến độ. Triển vọng đầu tư tích cực trong ngắn hạn nhưng cần thận trọng với rủi ro liên quan đến giao dịch nội bộ.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VTB_2021_consolidated', 'VTB', 2021, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là công ty mẹ (Tổng Công ty Cổ phần Điện tử và Tin học Việt Nam), tập trung vào thanh toán và nhận cổ tức, không có giao dịch bất thường đáng kể như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty đã trả hết nợ vay ngân hàng ngắn hạn và dài hạn vào cuối năm 2021, áp lực nợ vay thấp. Không có tài sản thế chấp nổi bậtn cho các khoản vay trong năm.', 'Giá trị hàng tồn kho giảm mạnh do doanh thu sụt giảm, nhưng vẫn có dự phòng cho hàng hóa. Dự án xây dựng dở dang (VTB Green Building) có giá trị đáng kể, tiềm ẩn rủi ro nếu dự án bị đình trệ.', 5, 'Doanh thu và lợi nhuận sau thuế của công ty mẹ giảm mạnh trong năm 2021, phản ánh khó khăn chung của ngành sản xuất điện tử. Công ty đã chủ động giảm nợ vay và cải thiện dòng tiền hoạt động kinh doanh. Tình hình tài chính cơ bản ổn định, nhưng triển vọng tăng trưởng phụ thuộc vào khả năng khôi phục doanh thu và quản lý hiệu quả các dự án đầu tư.'),
('VTB_2020_consolidated', 'VTB', 2020, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là thanh toán cổ tức cho Công ty mẹ và mua hàng hóa với một công ty cùng Tổng Công ty, với giá trị phát sinh trong năm và số dư cuối kỳ không quá lớn so với quy mô hoạt động. Không có dấu hiệu của các giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn đáng ngờ.', 'Nợ vay tài chính giảm mạnh từ 50.871 triệu đồng xuống còn 5.670 triệu đồng, cho thấy áp lực trả nợ giảm đáng kể. Các khoản vay đều có tài sản thế chấp rõ ràng là quyền sử dụng đất và tài sản gắn liền với đất tại nhà xưởng KCN Vĩnh Lộc. Khả năng thanh toán nợ được đảm bảo.', 'Hàng tồn kho giảm từ 136.573 triệu đồng xuống còn 110.061 triệu đồng. Đáng chú ý là chi phí xây dựng cơ bản dở dang tăng mạnh (từ 32.493 triệu lên 46.199 triệu), liên quan đến dự án nhà xưởng tại Cát Lái. Cần theo dõi tiến độ và hiệu quả của khoản đầu tư này, nhưng chưa có thông tin về sự ứ đọng hay trễ tiến độ.', 3, 'Tình hình tài chính của Công ty cải thiện đáng kể trong năm 2020. Doanh thu thuần và lợi nhuận sau thuế tăng trưởng mạnh. Nợ vay giảm rõ rệt, làm giảm rủi ro tài chính. Tồn kho giảm nhưng đầu tư xây dựng dở dang tăng, phản ánh chiến lược mở rộng sản xuất. Quản trị công ty có sự kiểm soát tốt, với các giao dịch với bên liên quan minh bạch và được công bố đầy đủ. Tuy nhiên, rủi ro tập trung vào tiến độ của các dự án xây dựng lớn.'),
('VTB_2020_parent', 'VTB', 2020, 'parent', 'Doanh nghiệp có phát sinh nhiều giao dịch mua bán hàng hóa, dịch vụ và cho vay với các công ty con và công ty liên quan. Giá trị giao dịch lớn, đặc biệt là phải thu khách hàng với Công ty Vitek - VTB Hà Nội có dự phòng giảm giá, cho thấy rủi ro khả năng thu hồi nợ. Cần theo dõi chặt chẽ tính minh bạch và công bằng của các giao dịch nội bộ này.', 'Nợ vay giảm đáng kể so với đầu năm, áp lực trả nợ thấp. Tài sản thế chấp chủ yếu là quyền sử dụng đất và tài sản gắn liền. Tuy nhiên, một phần lớn tài sản cố định đã được dùng thế chấp, làm giảm tính linh hoạt tài sản của công ty.', 'Giá trị hàng tồn kho lớn, chiếm tỷ trọng cao trong tài sản ngắn hạn, bao gồm cả thành phẩm và nguyên vật liệu. Doanh thu sụt giảm do Covid-19 có thể gây rủi ro ứ đọng và giảm giá trị tồn kho.', 4, 'Công ty hoạt động trong ngành sản xuất điện tử, chịu ảnh hưởng nặng nề từ đại dịch Covid-19 khiến doanh thu giảm mạnh. Tuy nhiên, biên lợi nhuận gộp vẫn ở mức cao và công ty có lãi. Cơ cấu vốn chủ sở hữu mạnh, nợ vay giảm. Các rủi ro chính nằm ở giao dịch bên liên quan phức tạp và lượng tồn kho lớn. Triển vọng trung hạn phụ thuộc vào sự phục hồi của chuỗi cung ứng và nhu cầu thị trường.'),
('VTB_2021_parent', 'VTB', 2021, 'parent', 'Doanh nghiệp có nhiều giao dịch với các công ty con, bao gồm bán hàng, mua hàng, và chia cổ tức. Tuy nhiên, không có thông tin về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Các giao dịch có vẻ được thực hiện theo giá thị trường.', 'Tại ngày 31/12/2021, công ty không có nợ vay, do đó rủi ro nợ thấp. Trước đó, công ty đã thanh toán hết nợ ngắn hạn và dài hạn, cho thấy khả năng quản lý nợ tốt.', 'Hàng tồn kho giảm đáng kể từ 76,1 tỷ đồng xuống 29,9 tỷ đồng, cho thấy tồn kho được kiểm soát tốt. Không có dự phòng giảm giá tồn kho, nhưng cần theo dõi tình hình bán hàng.', 3, 'Công ty có tình hình tài chính ổn định với lợi nhuận gộp cao, không nợ vay, và dòng tiền hoạt động kinh doanh dương. Tuy nhiên, doanh thu phụ thuộc nhiều vào các công ty con. Triển vọng đầu tư trung bình do ngành điện tử cạnh tranh cao.'),
('VTB_2019_consolidated', 'VTB', 2019, 'consolidated', 'Các giao dịch với bên liên quan không phức tạp. Công ty mẹ (Tổng Công ty Cổ phần Điện tử và Tin học Việt Nam) chiếm tỷ lệ sở hữu lớn và nhận cổ tức 16.2 tỷ VNĐ trong năm. Công ty có mua hàng từ Công ty CP Cơ Khí Điện Từ Phú Thọ Hòa (cùng Tổng Công ty) trị giá 1.2 tỷ VNĐ. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn với bên liên quan.', 'Tổng nợ vay tăng mạnh từ 0 lên 50.87 tỷ VNĐ trong năm 2019, tập trung vào vay dài hạn 17.28 tỷ VNĐ để đầu tư dự án Cát Lái và vay ngắn hạn 33.59 tỷ VNĐ bổ sung vốn lưu động. Áp lực nợ vay đáng kể với chi phí lãi vay 1.33 tỷ VNĐ. Tài sản thế chấp bao gồm quyền đòi nợ luân chuyển từ Toyota, Isuzu, Suzuki; hàng tồn kho luân chuyển; và quyền sử dụng đất tại KCN Vĩnh Lộc. Dự phòng phải trả ngắn hạn tăng từ 7.6 tỷ lên 14.8 tỷ VNĐ.', 'Hàng tồn kho tăng mạnh từ 112.39 tỷ lên 136.57 tỷ VNĐ, chủ yếu do thành phẩm tăng 13 tỷ VNĐ và hàng hóa tăng 24 tỷ VNĐ. Dự phòng giảm giá tồn kho giảm từ 948 triệu xuống 686 triệu VNĐ. Dự án nhà xưởng Cát Lái tăng vọt từ 1.9 tỷ lên 23 tỷ VNĐ, cần theo dõi tiến độ triển khai. Dự án VTB Green Building tương đối ổn định quanh 9.4 tỷ VNĐ.', 4, 'Công ty có doanh thu thuần giảm 33% (từ 536.5 tỷ xuống 359.6 tỷ VNĐ) nhưng biên lợi nhuận gộp cải thiện đáng kể từ 20.4% lên 34.7%, cho thấy thay đổi cơ cấu sản phẩm hướng đến sản phẩm có giá trị gia tăng cao hơn. Lợi nhuận sau thuế giảm 14% (từ 18.57 tỷ xuống 16 tỷ VNĐ). Dòng tiền hoạt động kinh doanh dương 7.28 tỷ VNĐ (so với âm 66.7 tỷ năm trước), cải thiện rõ rệt. Công ty đang trong giai đoạn đầu tư mở rộng mạnh với dự án nhà xưởng Cát Lái 23 tỷ VNĐ và vay nợ tăng vọt. Nợ vay ngắn hạn 33.59 tỷ VNĐ cần được theo dõi sát. Công ty có lịch sử chi trả cổ tức đều đặn (16.2 tỷ VNĐ năm 2019).'),
('VTB_2018_consolidated', 'VTB', 2018, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là bán hàng hóa và trả cổ tức, giá trị không quá lớn và không có dấu hiệu giao dịch bất thường hay giá chuyển nhượng không hợp lý.', 'Công ty không trình bày chi tiết nợ vay ngân hàng. Các khoản nợ phải trả chủ yếu là phải trả người bán và chi phí phải trả phát sinh từ hoạt động kinh doanh thương mại. Áp lực nợ ngắn hạn lớn nhưng chủ yếu là nợ thương mại.', 'Hàng tồn kho tăng nhẹ từ 108.694.816.847 VNĐ lên 113.340.040.189 VNĐ. Dự phòng giảm giá hàng tồn kho tăng từ 591.297.039 VNĐ lên 948.150.039 VNĐ, cho thấy một phần hàng tồn kho có nguy cơ giảm giá.', 4, 'Công ty ghi nhận doanh thu thuần giảm mạnh (từ 824.621 triệu VNĐ xuống 536.517 triệu VNĐ) nhưng lợi nhuận gộp tăng, biên lợi nhuận gộp cải thiện lên 20,4%. Dòng tiền hoạt động kinh doanh âm (-66.734 triệu VNĐ) do giảm mạnh phải trả người bán và tăng phải thu, bù đắp bằng dòng tiền đầu tư dương từ thu hồi cho vay và bán TSCĐ. Công ty có lịch sử trả cổ tức đều đặn. Tuy nhiên, rủi ro tập trung vào biến động tỷ giá và quản lý hàng tồn kho. Triển vọng trung bình, ổn định.'),
('VTB_2019_parent', 'VTB', 2019, 'parent', 'Doanh nghiệp có nhiều giao dịch với các bên liên quan, đặc biệt là các công ty con, bao gồm bán hàng, mua hàng, phạt lãi nợ quá hạn và cổ tức. Việc phạt lãi nợ quá hạn cho thấy có khả năng chậm thanh toán từ các công ty con. Tuy nhiên, không có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Tổng nợ vay ngắn hạn và dài hạn là 35,871,884,429 VND, chiếm khoảng 13.8% tổng tài sản. Nợ vay được đảm bảo bằng quyền sử dụng đất và tài sản gắn liền. Áp lực nợ vay không quá lớn, công ty có khả năng thanh toán dựa trên dòng tiền từ hoạt động kinh doanh.', 'Hàng tồn kho tăng 9.5% so với đầu năm, chủ yếu do tăng thành phẩm và nguyên liệu. Không có dự phòng giảm giá hàng tồn kho. Công ty cần theo dõi sát sao khả năng tiêu thụ để tránh ứ đọng.', 6, 'Công ty có cơ cấu tài sản và nguồn vốn tương đối lành mạnh, với tỷ lệ nợ vay không quá cao. Tuy nhiên, doanh thu giảm mạnh so với năm trước (từ 380 tỷ xuống 150 tỷ), lợi nhuận sau thuế giảm từ 13.2 tỷ xuống 7.4 tỷ. Công ty có nhiều giao dịch với bên liên quan và cần quản lý rủi ro tồn kho. Triển vọng đầu tư trung bình.'),
('VTB_2017_consolidated', 'VTB', 2017, 'consolidated', 'Giao dịch với công ty con Công ty CP Công nghệ Thông tin VTB có giá trị mua hàng rất lớn (462 tỷ VNĐ) so với bán hàng (15.6 tỷ VNĐ), cho thấy công ty con là nhà cung cấp chính. Các giao dịch với Tổng Công ty mẹ chỉ ở mức nhỏ (bán hàng 13.5 triệu VNĐ). Công ty trả cổ tức lớn cho cổ đông không kiểm soát (công ty con). Cần lưu ý rủi ro giao dịch nội bộ có thể không phản ánh giá trị thị trường fair.', 'Áp lực nợ vay thấp do cuối năm 2017 không còn nợ ngân hàng (so với 12 tỷ VNĐ đầu năm). Tuy nhiên, phải trả người bán chiếm tỷ trọng lớn (448 tỷ VNĐ cuối năm), phản ánh công ty chủ yếu dựa vào tín dụng thương mại từ nhà cung cấp chính Shenzhen Chuangwei. Công ty có tài sản thế chấp là TSCĐ hữu hình (18.4 tỷ VNĐ) và TSCĐ vô hình (21 tỷ VNĐ quyền sử dụng đất).', 'Hàng tồn kho giảm mạnh từ 205 tỷ VNĐ xuống 109 tỷ VNĐ, cho thấy công ty đã tiêu thụ tốt hoặc giảm dự trữ. Tuy nhiên, có khoản dự phòng giảm giá 591 triệu VNĐ cho hàng hóa ứ đọng. Dự án xây dựng dở dang (3.77 tỷ VNĐ) tăng nhẹ và chưa hoàn thành, cần theo dõi tiến độ dự án VTB Green Building và Nhà xưởng Cát Lái.', 5, 'Công ty CP Viettronics Tân Bình có kết quả kinh doanh cải thiện năm 2017 với lợi nhuận sau thuế 19.74 tỷ VNĐ (tăng 20% so với năm trước). Tỷ suất lợi nhuận gộp ~10.28% trong ngành điện tử. Công ty giảm được nợ vay ngân hàng, cải thiện dòng tiền hoạt động kinh doanh (72 tỷ VNĐ). Tuy nhiên, công ty phụ thuộc lớn vào nhà cung cấp Shenzhen Chuangwei (445 tỷ VNĐ nợ phải trả) và có giao dịch nội bộ lớn với công ty con. Cần theo dõi tiến độ các dự án xây dựng dở dang và khả năng thanh toán nợ thương mại.'),
('VTB_2018_parent', 'VTB', 2018, 'parent', 'Doanh nghiệp có giao dịch đáng kể với các công ty con và công ty mẹ, bao gồm mua bán hàng hóa, phạt lãi nợ quá hạn, thanh lý tài sản và chia cổ tức. Cần theo dõi các giao dịch này để đảm bảo tính công bằng và minh bạch.', 'Nợ vay chủ yếu là phải trả người bán và phải trả khác, không có khoản vay ngân hàng. Áp lực nợ thấp, khả năng thanh toán tốt với tài sản thế chấp không đáng kể.', 'Hàng tồn kho bao gồm nguyên liệu và thành phẩm, không có dự phòng giảm giá. Các dự án xây dựng dở dang như VTB Green Building đang trong quá trình xây dựng, cần theo dõi tiến độ và hiệu quả.', 5, 'Công ty có tình hình tài chính ổn định với tỷ suất lợi nhuận gộp khoảng 14.5%, nhưng doanh thu giảm mạnh so với năm trước. Nợ vay thấp và thanh khoản tốt, tuy nhiên rủi ro liên quan đến các giao dịch với bên liên quan cần được quản lý. Triển vọng đầu tư trung bình do ngành điện tử cạnh tranh cao.'),
('VTB_2017_parent', 'VTB', 2017, 'parent', 'Giao dịch với các bên liên quan có giá trị rất lớn: mua hàng từ Công ty CP Công nghệ Thông tin VTB (công ty con) lên tới 462.220 tỷ VNĐ trong năm 2017, chiếm tỷ trọng doanh thu rất cao. Công ty còn nợ Công ty CP Công nghệ Thông tin VTB 311.325 tỷ VNĐ ngắn hạn. Ngoài ra, Công ty có khoản nợ phải thu 37.489 tỷ VNĐ từ các công ty con. Mối quan hệ giao dịch mua-bán nội bộ tập trung chủ yếu vào một bên liên quan (CNTT VTB) tiềm ẩn rủi ro về giá chuyển nhượng và tính minh bạch. Tuy nhiên, chưa có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất.', 'Áp lực nợ vay thấp: Công ty đã trả hết khoản vay ngắn hạn 49.100 tỷ VNĐ tại Ngân hàng Ngoại thương Việt Nam trong năm 2017, số dư nợ vay cuối năm là 0 VNĐ. Tuy nhiên, Công ty có khoản phải trả ngắn hạn lớn (473.912 tỷ VNĐ) trong đó nợ phải trả nhà cung cấp Shenzhen Chuangwei 123.518 tỷ VNĐ và nợ công ty con CNTT VTB 311.325 tỷ VNĐ. Công ty có 69.700 tỷ VNĐ đầu tư nắm giữ đến đáo hạn (tiền gửi có kỳ hạn trên 3 tháng) cho thấy thanh khoản tốt. Tài sản thế chấp gồm nhà xưởng, quyền sử dụng đất và TSCĐ vô hình trị giá khoảng 39.450 tỷ VNĐ.', 'Hàng tồn kho giảm mạnh từ 104.121 tỷ VNĐ xuống 72.060 tỷ VNĐ (-30.8%), cho thấy Công ty đã giải phóng được lượng hàng tồn kho. Tuy nhiên, vẫn còn khoản xây dựng cơ bản dở dang 3.773 tỷ VNĐ bao gồm dự án VTB Green Building và nhà xưởng tại Cát Lái. Dự án mua đất tại KCN Cát Lái (8.330 tỷ VNĐ đã thanh toán) vẫn chưa hoàn thiện thủ tục thuê đất, đây là rủi ro tiềm ẩn về mặt pháp lý và tài sản.', 5, 'Công ty CP Viettronics Tân Bình có kết quả kinh doanh ổn định với doanh thu thuần 730.133 tỷ VNĐ và lợi nhuận sau thuế 16.672 tỷ VNĐ (tăng 5% so với năm trước). Tỷ suất lợi nhuận gộp đạt 6,3% - biên lợi nhuận mỏng đặc trưng cho ngành sản xuất/thương mại điện tử. Công ty đã giảm được nợ vay ngân hàng về 0 và có thanh khoản tốt với tiền gửi có kỳ hạn lớn. Rủi ro chính nằm ở: (1) phụ thuộc giao dịch nội bộ với công ty con CNTT VTB (chiếm tỷ trọng lớn trong mua hàng), (2) khoản nợ phải trả lớn cho nhà cung cấp nước ngoài Shenzhen Chuangwei, (3) dự án bất động sản chưa hoàn thiện thủ tục pháp lý. Lợi nhuận chưa phân phối giảm do chia cổ tức 30.252 tỷ VNĐ (tỷ lệ 20%). Triển vọng trung bình, phù hợp với nhà đầu tư thận trọng.');
PRAGMA foreign_keys = ON;
